import React, { useState, useEffect, useRef, useMemo } from "react";
import { createRoot } from "react-dom/client";
import { GoogleGenAI, Type, FunctionDeclaration, Modality, LiveServerMessage, Blob } from "@google/genai";

// --- Types ---

type Risk = {
  id: string; // internal UUID or timestamp
  risk_id: string;
  asset_category: string;
  asset: string;
  threat: string;
  vulnerability: string;
  risk_statement: string;
  likelihood_score: number;
  impact_score: number;
  inherent_risk: number;
  existing_controls: string;
  control_effectiveness: "weak" | "medium" | "strong";
  residual_risk: number;
  risk_level: string;
  treatment_option: string;
  action_owner: string;
  timeline: string;
  status: string;
  evidence_links: string[];
  mitigation_actions: string;
};

type ContextState = {
  organization: string;
  scope: string;
  risk_appetite: string;
  methodology: string;
  frameworks: string[];
};

// --- Helpers for Risk Logic ---

const calculateInherentRisk = (l: number, i: number) => l * i;

const controlFactor = (eff: string) => {
  switch (eff) {
    case "strong": return 0.5;
    case "medium": return 0.75;
    case "weak": default: return 1.0;
  }
};

const calculateResidualRisk = (inherent: number, eff: string) => {
  return Math.round(inherent * controlFactor(eff));
};

const riskLevelFromScore = (score: number) => {
  if (score <= 6) return "Low";
  if (score <= 14) return "Medium";
  if (score <= 20) return "High";
  return "Extreme";
};

const initialRiskState: Risk = {
  id: "",
  risk_id: "",
  asset_category: "",
  asset: "",
  threat: "",
  vulnerability: "",
  risk_statement: "",
  likelihood_score: 3,
  impact_score: 3,
  inherent_risk: 9,
  existing_controls: "",
  control_effectiveness: "medium",
  residual_risk: 7,
  risk_level: "Medium",
  treatment_option: "",
  action_owner: "",
  timeline: "",
  status: "Open",
  evidence_links: [],
  mitigation_actions: "",
};

// --- Library Generation (Based on CSV Patterns) ---
const RISK_TEMPLATES = [
  { cat: "IT Operations", threat: "Data Breach", vuln: "Weak Controls", l: 2, i: 4 },
  { cat: "Network", threat: "System Failure", vuln: "Human Error", l: 3, i: 5 },
  { cat: "Application Security", threat: "Phishing Attack", vuln: "Lack of Monitoring", l: 4, i: 1 },
  { cat: "Physical Security", threat: "Malware Infection", vuln: "Missing Encryption", l: 5, i: 2 },
  { cat: "People Risk", threat: "Zero-Day Exploit", vuln: "Legacy Systems", l: 1, i: 3 },
  { cat: "Compliance/Regulatory", threat: "Insider Threat", vuln: "Poor Network Segmentation", l: 2, i: 4 },
  { cat: "Data Privacy", threat: "DDoS Attack", vuln: "Weak Authentication", l: 3, i: 5 },
  { cat: "Cloud Security", threat: "Weak Passwords", vuln: "Insecure APIs", l: 4, i: 1 },
  { cat: "Third-Party Risk", threat: "Misconfiguration", vuln: "Third-party gaps", l: 5, i: 2 },
  { cat: "Cybersecurity", threat: "Unauthorized Access", vuln: "Unpatched Systems", l: 1, i: 3 },
];

function generateRiskLibrary(): Risk[] {
  const library: Risk[] = [];
  const totalRisks = 300;

  for (let i = 0; i < totalRisks; i++) {
    const template = RISK_TEMPLATES[i % RISK_TEMPLATES.length];
    const idNum = i + 1;
    const riskId = `R-${String(idNum).padStart(3, '0')}`;
    const assetName = `Asset ${idNum}`;
    const statement = `Risk that ${template.threat} exploiting ${template.vuln} affects ${assetName}.`;

    const inherent = calculateInherentRisk(template.l, template.i);
    // Default effectiveness 'medium'
    const residual = calculateResidualRisk(inherent, "medium");

    library.push({
      id: Date.now().toString() + "-" + i,
      risk_id: riskId,
      asset_category: template.cat,
      asset: assetName,
      threat: template.threat,
      vulnerability: template.vuln,
      risk_statement: statement,
      likelihood_score: template.l,
      impact_score: template.i,
      inherent_risk: inherent,
      existing_controls: "Standard controls applied",
      control_effectiveness: "medium",
      residual_risk: residual,
      risk_level: riskLevelFromScore(residual),
      treatment_option: "Treat",
      action_owner: "TBD",
      timeline: "",
      status: "Open",
      evidence_links: [],
      mitigation_actions: "",
    });
  }
  return library;
}

// --- Audio Helpers (Live API & TTS) ---

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// --- Heatmap Component ---
const Heatmap = ({ risks }: { risks: Risk[] }) => {
  // 5x5 Grid
  // Y-axis: Likelihood (5 down to 1)
  // X-axis: Impact (1 to 5)
  const grid = useMemo(() => {
    const map = new Map<string, number>();
    risks.forEach(r => {
        const key = `${r.likelihood_score}-${r.impact_score}`;
        map.set(key, (map.get(key) || 0) + 1);
    });
    return map;
  }, [risks]);

  const rows = [5, 4, 3, 2, 1];
  const cols = [1, 2, 3, 4, 5];

  const getCellColor = (l: number, i: number) => {
    const score = l * i; // Simple Inherent
    if (score >= 21) return "bg-red-600/80 text-white"; // Extreme
    if (score >= 15) return "bg-orange-500/80 text-white"; // High
    if (score >= 7) return "bg-yellow-500/80 text-slate-900"; // Medium
    return "bg-emerald-500/80 text-slate-900"; // Low
  };

  return (
    <div className="flex flex-col items-center">
      <div className="flex items-center gap-4">
        <div className="flex flex-col justify-center items-center h-full">
            <span className="text-xs font-bold text-slate-400 -rotate-90 whitespace-nowrap mb-8">Likelihood</span>
        </div>
        <div className="grid grid-cols-5 gap-1">
            {rows.map(l => (
                cols.map(i => {
                    const count = grid.get(`${l}-${i}`) || 0;
                    return (
                        <div 
                            key={`${l}-${i}`}
                            className={`w-12 h-12 md:w-16 md:h-16 flex items-center justify-center rounded border border-white/10 text-sm font-bold transition-transform hover:scale-105 cursor-default ${getCellColor(l, i)}`}
                            title={`Likelihood: ${l}, Impact: ${i} (${count} risks)`}
                        >
                            {count > 0 ? count : ""}
                        </div>
                    )
                })
            ))}
        </div>
      </div>
      <div className="mt-2 text-xs font-bold text-slate-400">Impact</div>
    </div>
  );
};

// --- Dashboard Component ---
const Dashboard = ({ risks }: { risks: Risk[] }) => {
    const total = risks.length;
    const byLevel = useMemo(() => {
        const counts = { Extreme: 0, High: 0, Medium: 0, Low: 0 };
        risks.forEach(r => {
            if (counts[r.risk_level as keyof typeof counts] !== undefined) {
                counts[r.risk_level as keyof typeof counts]++;
            }
        });
        return counts;
    }, [risks]);

    const byCategory = useMemo(() => {
        const counts: Record<string, number> = {};
        risks.forEach(r => {
            counts[r.asset_category] = (counts[r.asset_category] || 0) + 1;
        });
        return Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, 5); // Top 5
    }, [risks]);

    return (
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in duration-500">
            {/* KPI Cards */}
            <div className="space-y-4">
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                    <h3 className="text-slate-400 text-xs uppercase font-semibold">Total Risks</h3>
                    <div className="text-3xl font-bold text-slate-100">{total}</div>
                </div>
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                    <h3 className="text-slate-400 text-xs uppercase font-semibold">Critical (High/Extreme)</h3>
                    <div className="text-3xl font-bold text-red-400">
                        {byLevel.High + byLevel.Extreme}
                        <span className="text-xs text-slate-500 font-normal ml-2">
                             ({total > 0 ? Math.round(((byLevel.High + byLevel.Extreme) / total) * 100) : 0}%)
                        </span>
                    </div>
                </div>

                {/* Level Distribution Bar Chart */}
                <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800">
                    <h3 className="text-slate-400 text-xs uppercase font-semibold mb-3">Risk Distribution</h3>
                    <div className="space-y-2 text-xs">
                        {Object.entries(byLevel).map(([lvl, count]) => (
                            <div key={lvl} className="flex items-center gap-2">
                                <div className="w-16 text-slate-300">{lvl}</div>
                                <div className="flex-1 h-2 bg-slate-800 rounded-full overflow-hidden">
                                    <div 
                                        className={`h-full rounded-full ${
                                            lvl === 'Extreme' ? 'bg-red-500' :
                                            lvl === 'High' ? 'bg-orange-500' :
                                            lvl === 'Medium' ? 'bg-yellow-500' : 'bg-emerald-500'
                                        }`}
                                        style={{ width: `${total > 0 ? (Number(count) / total) * 100 : 0}%` }}
                                    />
                                </div>
                                <div className="w-8 text-right text-slate-400">{count}</div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Heatmap */}
            <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800 flex flex-col items-center justify-center lg:col-span-1">
                <h3 className="text-slate-400 text-xs uppercase font-semibold mb-4 self-start">Heatmap Overview</h3>
                <Heatmap risks={risks} />
            </div>

             {/* Top Categories */}
             <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-800 lg:col-span-1">
                <h3 className="text-slate-400 text-xs uppercase font-semibold mb-4">Top Risk Categories</h3>
                <div className="space-y-3">
                    {byCategory.map(([cat, count]) => (
                        <div key={cat} className="space-y-1">
                            <div className="flex justify-between text-xs text-slate-300">
                                <span>{cat}</span>
                                <span>{count}</span>
                            </div>
                            <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                <div 
                                    className="h-full bg-sky-500/60 rounded-full" 
                                    style={{ width: `${total > 0 ? (Number(count) / total) * 100 * 2 : 0}%` }} // Scale up for visibility
                                /> 
                            </div>
                        </div>
                    ))}
                    {byCategory.length === 0 && <div className="text-xs text-slate-500">No data available</div>}
                </div>
            </div>
        </div>
    )
}

// --- App Component ---

const App = () => {
  // Global State
  const [activeTab, setActiveTab] = useState<'assessment' | 'dashboard'>('assessment');
  const [context, setContext] = useState<ContextState>({
    organization: "",
    scope: "",
    risk_appetite: "",
    methodology: "qualitative",
    frameworks: ["ISO 31000"],
  });

  const [riskRegister, setRiskRegister] = useState<Risk[]>([]);
  const [currentRisk, setCurrentRisk] = useState<Risk>({ ...initialRiskState });
  const [isEditing, setIsEditing] = useState(false);
  const [selectedRiskIndex, setSelectedRiskIndex] = useState<number | null>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState("");
  const [filterLevel, setFilterLevel] = useState("All");

  // Highlight State for AI Guidance
  const [activeField, setActiveField] = useState<string | null>(null);

  // AI State
  const [aiOutput, setAiOutput] = useState("");
  const [aiLoading, setAiLoading] = useState(false);
  const [jsonOutput, setJsonOutput] = useState("");
  const [ttsLoading, setTtsLoading] = useState(false);

  // Live API State
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLiveConnecting, setIsLiveConnecting] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const liveSessionRef = useRef<any>(null); 
  const nextStartTimeRef = useRef<number>(0);
  const liveSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Refs for data access inside Live API callbacks
  const contextRef = useRef(context);
  const riskRegisterRef = useRef(riskRegister);
  const currentRiskRef = useRef(currentRisk);
  const selectedRiskIndexRef = useRef(selectedRiskIndex);

  useEffect(() => {
    contextRef.current = context;
    riskRegisterRef.current = riskRegister;
    currentRiskRef.current = currentRisk;
    selectedRiskIndexRef.current = selectedRiskIndex;
  }, [context, riskRegister, currentRisk, selectedRiskIndex]);

  // Update calculated fields when inputs change
  useEffect(() => {
    const inherent = calculateInherentRisk(currentRisk.likelihood_score, currentRisk.impact_score);
    const residual = calculateResidualRisk(inherent, currentRisk.control_effectiveness);
    const level = riskLevelFromScore(residual);

    if (
      inherent !== currentRisk.inherent_risk ||
      residual !== currentRisk.residual_risk ||
      level !== currentRisk.risk_level
    ) {
      setCurrentRisk((prev) => ({
        ...prev,
        inherent_risk: inherent,
        residual_risk: residual,
        risk_level: level,
      }));
    }
  }, [
    currentRisk.likelihood_score,
    currentRisk.impact_score,
    currentRisk.control_effectiveness,
  ]);

  // Handlers
  const handleContextChange = (field: keyof ContextState, value: any) => {
    setContext((prev) => ({ ...prev, [field]: value }));
  };

  const toggleFramework = (fw: string) => {
    setContext(prev => {
        const has = prev.frameworks.includes(fw);
        return {
            ...prev,
            frameworks: has ? prev.frameworks.filter(f => f !== fw) : [...prev.frameworks, fw]
        }
    });
  }

  const handleRiskChange = (field: keyof Risk, value: any) => {
    setCurrentRisk((prev) => ({ ...prev, [field]: value }));
  };

  const saveRisk = () => {
    let updatedRegister;
    if (selectedRiskIndex !== null) {
      updatedRegister = [...riskRegister];
      updatedRegister[selectedRiskIndex] = { ...currentRisk };
    } else {
      updatedRegister = [...riskRegister, { ...currentRisk, id: Date.now().toString() }];
    }

    setRiskRegister(updatedRegister);
    clearForm();
  };

  const editRiskObj = (risk: Risk) => {
      const idx = riskRegister.findIndex(r => r.id === risk.id);
      if (idx !== -1) {
          setSelectedRiskIndex(idx);
          setCurrentRisk({...riskRegister[idx]});
          setIsEditing(true);
      }
  }

  const clearForm = () => {
    setSelectedRiskIndex(null);
    setCurrentRisk({ ...initialRiskState });
    setIsEditing(false);
    setAiOutput("");
    setActiveField(null);
  };

  const loadLibrary = () => {
    const newRisks = generateRiskLibrary();
    const updated = [...riskRegister, ...newRisks];
    setRiskRegister(updated);
    return `Loaded ${newRisks.length} risks into the register.`;
  }

  const generateJson = () => {
    const exportData = {
      risk_assessment: {
        version: "2.0",
        generated_at: new Date().toISOString(),
        frameworks_used: contextRef.current.frameworks,
        context: contextRef.current,
        risk_register_summary: {
            total_risks: riskRegisterRef.current.length,
            high_extreme_count: riskRegisterRef.current.filter(r => r.risk_level === "High" || r.risk_level === "Extreme").length
        },
        risk_register: riskRegisterRef.current,
      },
    };
    const jsonStr = JSON.stringify(exportData, null, 2);
    setJsonOutput(jsonStr);
    return `Report generated with ${riskRegisterRef.current.length} risks.`;
  };

  const scrollToSection = (sectionId: string) => {
      const el = document.getElementById(sectionId);
      if (el) el.scrollIntoView({ behavior: 'smooth' });
  }

  // --- Filter Logic ---
  const filteredRisks = useMemo(() => {
      return riskRegister.filter(r => {
          const matchesSearch = 
            r.risk_id.toLowerCase().includes(searchTerm.toLowerCase()) || 
            r.asset.toLowerCase().includes(searchTerm.toLowerCase()) ||
            r.threat.toLowerCase().includes(searchTerm.toLowerCase());

          const matchesLevel = filterLevel === "All" || r.risk_level === filterLevel;

          return matchesSearch && matchesLevel;
      });
  }, [riskRegister, searchTerm, filterLevel]);

  // --- Style Helper for AI Highlighting ---
  const getFieldClass = (fieldId: string, baseClass: string = "mt-1 w-full rounded-lg bg-slate-950 border border-slate-700 px-2 py-1.5 text-sm focus:border-emerald-500 outline-none transition-all duration-500") => {
    if (activeField === fieldId) {
      // Warm light glow (Amber/Gold)
      return `${baseClass} ring-2 ring-amber-500 shadow-[0_0_25px_rgba(245,158,11,0.6)] border-amber-500 scale-[1.02] bg-slate-900 z-10 relative`;
    }
    return baseClass;
  };

  // --- Gemini 2.5 Logic ---

  const callGemini = async () => {
    if (selectedRiskIndex === null) {
      setAiOutput("Please select a risk from the table to analyze.");
      return;
    }

    setAiLoading(true);
    setAiOutput("Analyzing risk with Gemini...");

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const riskToAnalyze = riskRegister[selectedRiskIndex];
      const fwString = context.frameworks.join(" & ");

      const prompt = `
You are an expert GRC & Cybersecurity Risk Consultant following ${fwString}.

Given this risk, provide:
1) A short explanation of the risk in business language.
2) Recommended mitigation / treatment actions (bullet points) aligned with ${fwString}.
3) Residual risk considerations.
4) Specific compliance controls from ${fwString} (e.g. NCA ECC-1:2018 or ISO 27001 Annex A controls) that apply.

Risk data (JSON):
${JSON.stringify(riskToAnalyze, null, 2)}
`;

      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt,
      });

      setAiOutput(response.text || "No response generated.");
    } catch (error) {
      setAiOutput(`Error: ${error instanceof Error ? error.message : "Unknown error"}`);
    } finally {
      setAiLoading(false);
    }
  };

  // --- TTS Logic ---

  const speakAiOutput = async () => {
    if (!aiOutput) return;
    setTtsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: aiOutput.substring(0, 4000) }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const audioBuffer = await decodeAudioData(decode(base64Audio), audioCtx, 24000, 1);

        const source = audioCtx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioCtx.destination);
        source.start();
      }
    } catch (err) {
      console.error("TTS Error:", err);
      alert("Failed to generate speech.");
    } finally {
      setTtsLoading(false);
    }
  };

  // --- Live API Logic ---

  const toggleLiveConnection = async () => {
    if (isLiveConnected || isLiveConnecting) {
      // Disconnect
      if (liveSessionRef.current) {
        liveSessionRef.current = null;
      }

      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
      }
      if (audioContextRef.current) {
        audioContextRef.current.close();
        audioContextRef.current = null;
      }
      if (processorRef.current) {
        processorRef.current.disconnect();
        processorRef.current = null;
      }
      setIsLiveConnected(false);
      setIsLiveConnecting(false);
      setActiveField(null);
      return;
    }

    // Connect
    setIsLiveConnecting(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // --- Function Declarations for Navigation & Actions ---

      const getAssessmentTool: FunctionDeclaration = {
        name: "get_risk_assessment",
        description: "Get the full risk assessment data (context, frameworks, risks).",
        parameters: { type: Type.OBJECT, properties: {} },
      };

      const generateReportTool: FunctionDeclaration = {
        name: "generate_report",
        description: "Trigger JSON export and display it.",
        parameters: { type: Type.OBJECT, properties: {} },
      };

      const scrollToSectionTool: FunctionDeclaration = {
        name: "scroll_to_section",
        description: "Scroll to a specific section: 'context', 'form', 'register', 'matrix'.",
        parameters: {
          type: Type.OBJECT,
          properties: {
             section: { type: Type.STRING, enum: ["context", "form", "register", "matrix"] }
          },
          required: ["section"]
        }
      };

      const setFocusFieldTool: FunctionDeclaration = {
        name: "set_focus_field",
        description: "Highlight a specific UI input field to show the user what is being discussed.",
        parameters: {
          type: Type.OBJECT,
          properties: {
            field_id: { 
                type: Type.STRING, 
                description: "The ID of the field to highlight (e.g., 'ctx_org', 'ctx_scope', 'risk_threat', 'risk_likelihood', etc.)",
                enum: [
                    "ctx_org", "ctx_scope", "ctx_appetite", 
                    "risk_id", "risk_category", "risk_asset", "risk_threat", "risk_vuln", "risk_statement",
                    "risk_likelihood", "risk_impact", "risk_effectiveness", "risk_controls", 
                    "risk_treatment", "risk_owner", "risk_duedate", "risk_status", "risk_mitigation"
                ]
            }
          },
          required: ["field_id"]
        }
      };

      const selectRiskTool: FunctionDeclaration = {
        name: "select_risk",
        description: "Select a risk by ID (e.g. 'R-005') to view or edit.",
        parameters: {
          type: Type.OBJECT,
          properties: {
            risk_id: { type: Type.STRING }
          },
          required: ["risk_id"]
        }
      };

      const updateContextTool: FunctionDeclaration = {
        name: "update_context_info",
        description: "Update context fields like organization, scope, or appetite.",
        parameters: {
          type: Type.OBJECT,
          properties: {
             field: { type: Type.STRING, enum: ["organization", "scope", "risk_appetite"] },
             value: { type: Type.STRING }
          },
          required: ["field", "value"]
        }
      };

      const manageFrameworksTool: FunctionDeclaration = {
        name: "manage_frameworks",
        description: "Add or remove a framework (ISO 31000, NCA ECC, etc).",
        parameters: {
          type: Type.OBJECT,
          properties: {
            framework: { type: Type.STRING, enum: ["ISO 31000", "NCA ECC", "ISO 27001"] },
            action: { type: Type.STRING, enum: ["add", "remove"] }
          },
          required: ["framework", "action"]
        }
      };

      const updateFormFieldTool: FunctionDeclaration = {
        name: "update_form_field",
        description: "Update the currently active risk form field.",
        parameters: {
          type: Type.OBJECT,
          properties: {
            field: { type: Type.STRING, description: "Field name (threat, asset, likelihood_score, etc)" },
            value: { type: Type.STRING, description: "Value. Use strings for text, number-strings for scores." }
          },
          required: ["field", "value"]
        }
      };

      const saveRiskTool: FunctionDeclaration = {
        name: "save_risk_form",
        description: "Save the current risk form (commit changes or add new).",
        parameters: { type: Type.OBJECT, properties: {} }
      };

      const clearFormTool: FunctionDeclaration = {
        name: "clear_form",
        description: "Clear the form and deselect risk.",
        parameters: { type: Type.OBJECT, properties: {} }
      };

      const loadLibraryTool: FunctionDeclaration = {
        name: "load_risk_library",
        description: "Load the standard library of 300+ risks.",
        parameters: { type: Type.OBJECT, properties: {} }
      }

      // Audio Setup
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputCtx; 

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const source = inputCtx.createMediaStreamSource(stream);
      const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = scriptProcessor;

      scriptProcessor.connect(inputCtx.destination);
      source.connect(scriptProcessor);

      // Connect to Live API
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: `You are an AI GRC Consultant acting as a Guided Assessment Wizard.

          CORE BEHAVIOR:
          1.  **Guided Flow**: You must guide the user step-by-step through the assessment. Do not skip steps.
          2.  **Highlighting**: BEFORE asking a question about a field, you MUST call \`set_focus_field\` to highlight it visually (make it glow).
          3.  **Interaction Loop**:
              -   Highlight Field -> Ask Question -> Wait for User -> Update Field -> Confirm -> Move to Next Field.

          PHASE 1: ESTABLISH CONTEXT
          -   Start immediately with **Step 1: Establish Context**.
          -   Field 1: Organization Name (\`ctx_org\`). Call \`set_focus_field('ctx_org')\`, ask "What is the organization name?", use \`update_context_info\`.
          -   Field 2: Scope (\`ctx_scope\`). Call \`set_focus_field('ctx_scope')\`, ask "What is the scope?", use \`update_context_info\`.
          -   Field 3: Risk Appetite (\`ctx_appetite\`). Call \`set_focus_field('ctx_appetite')\`, ask about appetite.

          PHASE 2: RISK ASSESSMENT (NEW OR EXISTING)
          -   Ask if the user wants to add a new risk or assess existing ones.
          -   If **Existing Risks**:
              -   Load library if empty.
              -   Iterate through risks one by one.
              -   Use \`select_risk\`.
              -   Go field-by-field for that risk (Threat -> Vulnerability -> Impact -> Likelihood -> Effectiveness -> Controls).
              -   Highlight each using \`set_focus_field\` (e.g. \`risk_threat\`, \`risk_likelihood\`) as you discuss it.
              -   Ask user to validate or update. Use \`update_form_field\`.
              -   Save using \`save_risk_form\`.
              -   Move to next risk.

          TOOLS:
          - Use \`set_focus_field(field_id)\` extensively to show the user where we are.
          - Use \`update_context_info\` and \`update_form_field\` to write down user answers.
          - Use \`scroll_to_section\` to move the view.
          `,
          tools: [{ 
            functionDeclarations: [
                getAssessmentTool, 
                generateReportTool,
                scrollToSectionTool,
                setFocusFieldTool,
                selectRiskTool,
                updateContextTool,
                manageFrameworksTool,
                updateFormFieldTool,
                saveRiskTool,
                clearFormTool,
                loadLibraryTool
            ] 
          }],
        },
        callbacks: {
          onopen: () => {
            console.log("Live API Connected");
            setIsLiveConnected(true);
            setIsLiveConnecting(false);
          },
          onclose: () => {
            console.log("Live API Closed");
            setIsLiveConnected(false);
          },
          onerror: (err) => {
            console.error("Live API Error:", err);
            setIsLiveConnected(false);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Audio
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
              if (outputCtx.state === 'suspended') await outputCtx.resume();
              const audioBuffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const sourceNode = outputCtx.createBufferSource();
              sourceNode.buffer = audioBuffer;
              sourceNode.connect(outputCtx.destination);
              sourceNode.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;

              liveSourcesRef.current.add(sourceNode);
              sourceNode.onended = () => liveSourcesRef.current.delete(sourceNode);
            }

            if (message.serverContent?.interrupted) {
               liveSourcesRef.current.forEach(node => { try { node.stop(); } catch(e) {} });
               liveSourcesRef.current.clear();
               nextStartTimeRef.current = 0;
            }

            // Tools
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                let result: any = { status: "ok" };
                const args = fc.args as any;

                try {
                    switch (fc.name) {
                        case "set_focus_field":
                            setActiveField(args.field_id);
                            // Auto-scroll logic if needed
                            if (args.field_id.startsWith('ctx')) scrollToSection('context-section');
                            if (args.field_id.startsWith('risk')) scrollToSection('form-section');
                            result = { message: `Highlighted ${args.field_id}` };
                            break;
                        case "get_risk_assessment":
                            result = {
                                context: contextRef.current,
                                risk_count: riskRegisterRef.current.length,
                                // Send summary if too large
                                risks_summary: riskRegisterRef.current.map(r => ({id: r.risk_id, title: r.threat, level: r.risk_level})) 
                            };
                            break;
                        case "generate_report":
                            const repMsg = generateJson();
                            scrollToSection("form"); // Scroll down to JSON area roughly (or add specific ID)
                            result = { message: repMsg };
                            break;
                        case "scroll_to_section":
                            scrollToSection(args.section === 'matrix' ? 'matrix-section' : 
                                           args.section === 'register' ? 'register-section' :
                                           args.section === 'context' ? 'context-section' : 'form-section');
                            result = { message: `Scrolled to ${args.section}` };
                            break;
                        case "select_risk":
                            const idx = riskRegisterRef.current.findIndex(r => r.risk_id === args.risk_id);
                            if (idx !== -1) {
                                setSelectedRiskIndex(idx);
                                setCurrentRisk({ ...riskRegisterRef.current[idx] });
                                setIsEditing(true);
                                scrollToSection('form-section'); // Bring form into view
                                result = { message: `Selected risk ${args.risk_id}` };
                            } else {
                                result = { error: "Risk ID not found" };
                            }
                            break;
                        case "update_context_info":
                            setContext(prev => ({...prev, [args.field]: args.value}));
                            result = { message: `Updated ${args.field}` };
                            break;
                        case "manage_frameworks":
                             setContext(prev => {
                                const has = prev.frameworks.includes(args.framework);
                                if (args.action === 'add' && !has) return {...prev, frameworks: [...prev.frameworks, args.framework]};
                                if (args.action === 'remove' && has) return {...prev, frameworks: prev.frameworks.filter(f => f !== args.framework)};
                                return prev;
                            });
                            result = { message: `${args.action}ed ${args.framework}` };
                            break;
                        case "update_form_field":
                            setCurrentRisk(prev => ({
                                ...prev, 
                                [args.field]: (args.field.includes('score')) ? Number(args.value) : args.value 
                            }));
                            result = { message: `Updated ${args.field} to ${args.value}` };
                            break;
                        case "save_risk_form":
                            // We need to use Refs to emulate the save logic because we are in a closure
                            const curR = currentRiskRef.current;
                            const selIdx = selectedRiskIndexRef.current;
                            let newReg = [...riskRegisterRef.current];

                            if (selIdx !== null) {
                                newReg[selIdx] = { ...curR };
                            } else {
                                newReg.push({ ...curR, id: Date.now().toString() });
                            }
                            setRiskRegister(newReg);

                            // Reset form
                            setSelectedRiskIndex(null);
                            setCurrentRisk({ ...initialRiskState });
                            setIsEditing(false);
                            setAiOutput("");

                            result = { message: "Risk saved successfully." };
                            break;
                        case "clear_form":
                             setSelectedRiskIndex(null);
                             setCurrentRisk({ ...initialRiskState });
                             setIsEditing(false);
                             setAiOutput("");
                             result = { message: "Form cleared." };
                             break;
                        case "load_risk_library":
                             const newR = generateRiskLibrary();
                             const merged = [...riskRegisterRef.current, ...newR];
                             setRiskRegister(merged);
                             result = { message: "Library loaded." };
                             break;
                        default:
                            result = { error: "Unknown tool" };
                    }
                } catch (err) {
                    console.error("Tool execution error", err);
                    result = { error: "Failed to execute action on app." };
                }

                sessionPromise.then(session => {
                  session.sendToolResponse({
                    functionResponses: {
                      id: fc.id,
                      name: fc.name,
                      response: { result }
                    }
                  });
                });
              }
            }
          }
        }
      });

      scriptProcessor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        const pcmBlob = createBlob(inputData);
        sessionPromise.then(session => {
          session.sendRealtimeInput({ media: pcmBlob });
        });
      };

      liveSessionRef.current = {}; 

    } catch (e) {
      console.error("Connection failed", e);
      setIsLiveConnecting(false);
      setIsLiveConnected(false);
    }
  };

