                    alt="Profile" 
                    className="w-20 h-20 rounded-full bg-slate-800 object-cover border-2 border-slate-700" 
                    onError={(e) => (e.currentTarget.src = "https://via.placeholder.com/100?text=User")}
                 />
                 <div>
