// --- DocumentManager Component ---
const DocumentManager = ({ user }: { user: User }) => {
    const [files, setFiles] = useState<UserFile[]>([]);
    const [uploading, setUploading] = useState(false);
    const [progress, setProgress] = useState("");
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Subscribe to Files
    useEffect(() => {
        const q = query(
            collection(db, "users", user.uid, "files"),
            orderBy("uploadedAt", "desc")
        );
        const unsubscribe = onSnapshot(q, (snapshot) => {
            const loadedFiles = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            } as UserFile));
            setFiles(loadedFiles);
        });
        return () => unsubscribe();
    }, [user]);

    const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setUploading(true);
        setProgress("Uploading...");

        try {
            // 1. Upload to Storage
            const storagePath = `user_uploads/${user.uid}/${file.name}`;
            const storageRef = ref(storage, storagePath);
            const snapshot = await uploadBytes(storageRef, file);
            const downloadUrl = await getDownloadURL(snapshot.ref);

            setProgress("Analyzing with AI...");

            // 2. AI Summarization
            let aiSummary = "";
            const isImage = file.type.startsWith("image/");
            const isText = file.type.startsWith("text/") || 
                           file.name.endsWith(".json") || 
                           file.name.endsWith(".md") ||
                           file.name.endsWith(".csv");

            if (isImage || isText) {
                try {
                    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

                    let contentPart;
                    if (isImage) {
                        const base64 = await readFileAsBase64(file);
                        contentPart = { inlineData: { mimeType: file.type, data: base64 } };
                    } else {
                        const text = await readFileAsText(file);
                        contentPart = { text: text.substring(0, 30000) }; // Limit text length
                    }

                    const response = await ai.models.generateContent({
                        model: "gemini-2.5-flash",
                        contents: {
                            parts: [
                                contentPart,
                                { text: "Provide a concise summary of this document, focusing on risk assessment relevance. If it's data, summarize key trends. If it's an image, describe potential hazards or context." }
                            ]
                        }
                    });
                    aiSummary = response.text || "No summary available.";
                } catch (err) {
                    console.error("AI Summary failed", err);
                    aiSummary = "AI analysis failed or not available for this file content.";
                }
            } else {
                aiSummary = "AI summary not supported for this file type.";
            }

            setProgress("Saving record...");

            // 3. Save to Firestore
            await addDoc(collection(db, "users", user.uid, "files"), {
                fileName: file.name,
                storagePath,
                downloadUrl,
                size: file.size,
                type: file.type,
                uploadedAt: new Date().toISOString(),
                notes: "",
                aiSummary
            });

            setProgress("Done!");
            if (fileInputRef.current) fileInputRef.current.value = "";

        } catch (error) {
            console.error(error);
            alert("Failed to upload file.");
        } finally {
            setUploading(false);
            setTimeout(() => setProgress(""), 2000);
        }
    };

    const handleDelete = async (file: UserFile) => {
        if (!window.confirm(`Delete ${file.fileName}?`)) return;
        try {
            // Delete from Storage
            const storageRef = ref(storage, file.storagePath);
            await deleteObject(storageRef);

            // Delete from Firestore
            await deleteDoc(doc(db, "users", user.uid, "files", file.id));
        } catch (error) {
            console.error("Delete failed", error);
            alert("Failed to delete file. It might already be gone.");
        }
    };

    const updateNotes = async (fileId: string, newNotes: string) => {
        try {
            const docRef = doc(db, "users", user.uid, "files", fileId);
            await updateDoc(docRef, { notes: newNotes });
        } catch (error) {
            console.error("Update notes failed", error);
        }
    };

    return (
        <div className="space-y-6">
            <div className="bg-slate-900/70 rounded-xl border border-slate-800 p-6">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
                    <div>
                        <h2 className="text-xl font-bold text-white">Document History</h2>
                        <p className="text-sm text-slate-400">Manage evidence, reports, and risk artifacts.</p>
                    </div>
                    <div className="flex items-center gap-4">
                        {uploading && <span className="text-xs text-sky-400 animate-pulse">{progress}</span>}
                        <label className={`px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-500 transition-colors text-sm font-medium cursor-pointer ${uploading ? 'opacity-50 pointer-events-none' : ''}`}>
                            {uploading ? "Uploading..." : "Upload File"}
                            <input 
                                ref={fileInputRef}
                                type="file" 
                                className="hidden" 
                                onChange={handleUpload}
                                disabled={uploading}
                            />
                        </label>
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="text-xs text-slate-500 uppercase border-b border-slate-800">
                                <th className="px-4 py-3">File Name</th>
                                <th className="px-4 py-3">Uploaded</th>
                                <th className="px-4 py-3">Size</th>
                                <th className="px-4 py-3 w-1/3">AI Summary / Notes</th>
                                <th className="px-4 py-3 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800 text-sm">
                            {files.map(file => (
                                <tr key={file.id} className="hover:bg-slate-800/30 transition-colors">
                                    <td className="px-4 py-3">
                                        <div className="flex items-center gap-2">
                                            <span className="text-2xl">
                                                {file.type.includes('image') ? '🖼️' : 
                                                 file.type.includes('pdf') ? '📄' : 
                                                 file.type.includes('text') ? '📝' : '📁'}
                                            </span>
                                            <a href={file.downloadUrl} target="_blank" rel="noreferrer" className="text-sky-400 hover:underline font-medium truncate max-w-[150px] block" title={file.fileName}>
                                                {file.fileName}
                                            </a>
                                        </div>
                                    </td>
                                    <td className="px-4 py-3 text-slate-400 whitespace-nowrap">
                                        {new Date(file.uploadedAt).toLocaleDateString()}
                                    </td>
                                    <td className="px-4 py-3 text-slate-400 whitespace-nowrap">
                                        {(file.size / 1024).toFixed(1)} KB
                                    </td>
                                    <td className="px-4 py-3">
                                        <div className="space-y-2">
                                            {file.aiSummary && (
                                                <div className="text-xs bg-slate-800/50 p-2 rounded border border-slate-700/50 text-slate-300">
                                                    <span className="text-sky-500 font-bold mr-1">AI:</span>
                                                    {file.aiSummary}
                                                </div>
                                            )}
                                            <input 
                                                type="text" 
                                                placeholder="Add notes..."
                                                defaultValue={file.notes}
                                                className="w-full bg-transparent border-b border-slate-700 focus:border-emerald-500 text-xs text-slate-300 outline-none py-1 transition-colors"
                                                onBlur={(e) => updateNotes(file.id, e.target.value)}
                                            />
                                        </div>
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="flex justify-end gap-2">
                                            <a 
                                                href={file.downloadUrl} 
                                                target="_blank" 
                                                rel="noreferrer"
                                                className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-700 rounded transition-colors"
                                                title="Download"
                                            >
                                                ⬇️
                                            </a>
                                            <button 
                                                onClick={() => handleDelete(file)}
                                                className="p-1.5 text-slate-400 hover:text-red-400 hover:bg-red-900/20 rounded transition-colors"
                                                title="Delete"
                                            >
                                                🗑️
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {files.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="text-center py-8 text-slate-500">
                                        No files uploaded yet. Upload evidence or reports to get started.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

