  }

  // --- Filter Logic ---
  const filteredRisks = useMemo(() => {
      return riskRegister.filter(r => {
          const matchesSearch = 
            r.risk_id.toLowerCase().includes(searchTerm.toLowerCase()) || 
            r.asset.toLowerCase().includes(searchTerm.toLowerCase()) ||
            r.threat.toLowerCase().includes(searchTerm.toLowerCase());

          const matchesLevel = filterLevel === "All" || r.risk_level === filterLevel;

          return matchesSearch && matchesLevel;
      });
  }, [riskRegister, searchTerm, filterLevel]);

  // --- Style Helper for AI Highlighting ---
  const getFieldClass = (fieldId: string, baseClass: string = "mt-1 w-full rounded-lg bg-slate-950 border border-slate-700 px-2 py-1.5 text-sm focus:border-emerald-500 outline-none transition-all duration-500") => {
