                  >
                    Sign In
                  </button>
              )}
              {user && (
                  <button 
                    onClick={logout}
                    className="px-3 py-1.5 bg-slate-800 hover:bg-red-900/40 text-slate-400 hover:text-red-400 text-xs rounded-lg border border-slate-700 transition-colors"
                  >
                    Sign Out
                  </button>
              )}

              <div className="w-[1px] h-6 bg-slate-800 mx-1"></div>

              <button 
                  onClick={() => setActiveTab('assessment')}
                  className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${activeTab === 'assessment' ? 'bg-emerald-500 text-slate-900' : 'bg-slate-800 text-slate-400 hover:text-slate-200'}`}
              >
