              <button 
                  onClick={() => setActiveTab('dashboard')}
                  className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${activeTab === 'dashboard' ? 'bg-sky-500 text-slate-900' : 'bg-slate-800 text-slate-400 hover:text-slate-200'}`}
              >
                  Dashboard
              </button>
              {user && (
