                        <span className="text-2xl text-slate-600">📷</span>
                    )}
                 </div>
                 <label className="cursor-pointer text-xs text-sky-400 hover:text-sky-300">
                    <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
                    {photoFile ? "Change Photo" : "Upload Photo"}
                 </label>
              </div>

              <div>
                <label className="block text-xs text-slate-400 mb-1">Full Name</label>
                <input
                  type="text"
                  required
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:border-sky-500 outline-none transition-colors"
                  placeholder="John Doe"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>
            </div>
          )}

          <div>
            <label className="block text-xs text-slate-400 mb-1">Email Address</label>
            <input
              type="email"
              required
              className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:border-sky-500 outline-none transition-colors"
