  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLiveConnecting, setIsLiveConnecting] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [showAuthModal, setShowAuthModal] = useState(false);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const liveSessionRef = useRef<any>(null); 
  const nextStartTimeRef = useRef<number>(0);
  const liveSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const contextRef = useRef(context);
  const riskRegisterRef = useRef(riskRegister);
  const currentRiskRef = useRef(currentRisk);
  const selectedRiskIndexRef = useRef(selectedRiskIndex);

  // Auth Effect
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setAuthLoading(true);
      if (currentUser && !currentUser.emailVerified) {
         await signOut(auth);
         setUser(null);
         setUserProfile(null);
      } else {
         setUser(currentUser);
         if (currentUser) {
            try {
              const docSnap = await getDoc(doc(db, "users", currentUser.uid));
              if (docSnap.exists()) setUserProfile(docSnap.data() as UserProfile);
            } catch (e) { console.error(e); }
          }
      }
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    contextRef.current = context;
    riskRegisterRef.current = riskRegister;
    currentRiskRef.current = currentRisk;
    selectedRiskIndexRef.current = selectedRiskIndex;
  }, [context, riskRegister, currentRisk, selectedRiskIndex]);

  // Calculations
  useEffect(() => {
    const inhScore = calculateScore(currentRisk.inherent_likelihood, currentRisk.inherent_impact);
    const resScore = calculateScore(currentRisk.residual_likelihood, currentRisk.residual_impact);

    if (inhScore !== currentRisk.inherent_score || resScore !== currentRisk.residual_score) {
      setCurrentRisk((prev) => ({ ...prev, inherent_score: inhScore, residual_score: resScore }));
    }
  }, [currentRisk.inherent_likelihood, currentRisk.inherent_impact, currentRisk.residual_likelihood, currentRisk.residual_impact]);

  // Handlers
  const handleContextChange = (field: keyof ContextState, value: any) => setContext((prev) => ({ ...prev, [field]: value }));
  const handleRiskChange = (field: keyof Risk, value: any) => setCurrentRisk((prev) => ({ ...prev, [field]: value }));
  const openAuthModal = () => setShowAuthModal(true);
  const logout = async () => { await signOut(auth); setActiveTab('assessment'); };

  const saveRisk = () => {
    let updatedRegister;
    if (selectedRiskIndex !== null) {
      updatedRegister = [...riskRegister];
      updatedRegister[selectedRiskIndex] = { ...currentRisk };
    } else {
      updatedRegister = [...riskRegister, { ...currentRisk, id: Date.now().toString() }];
    }
    setRiskRegister(updatedRegister);
    clearForm();
  };

  const editRiskObj = (risk: Risk) => {
      const idx = riskRegister.findIndex(r => r.id === risk.id);
      if (idx !== -1) {
          setSelectedRiskIndex(idx);
          setCurrentRisk({...riskRegister[idx]});
          setIsEditing(true);
          document.getElementById('form-section')?.scrollIntoView({ behavior: 'smooth' });
      }
  }

  const clearForm = () => {
    setSelectedRiskIndex(null);
    setCurrentRisk({ ...initialRiskState });
    setIsEditing(false);
    setActiveField(null);
  };

  // --- Virtual Workflow Logic ---
  const performVirtualAudit = () => {
    if (!currentRisk.risk_title || !currentRisk.risk_owner) {
      alert("Virtual Auditor: Risk Title and Owner are mandatory for review.");
      return;
    }

    // Simulate AI check
    const newSignatures = [...currentRisk.signatures];
    newSignatures[1] = { // Virtual CISO
        name: "Virtual CISO (AI)",
        role: "Reviewer",
        date: new Date().toLocaleDateString(),
        status: "Signed"
    };

    setCurrentRisk(prev => ({
        ...prev,
        signatures: newSignatures,
        status: "Pending Review",
        remarks: prev.remarks + "\n[Virtual Auditor]: Validated field completeness. Ready for CIO."
    }));
    alert("Virtual Auditor has validated the document. Marked as 'Signed' by Virtual CISO.");
  };

  const digitalSign = (role: string) => {
      if (!user) { alert("Please sign in to sign."); return; }

      const idx = currentRisk.signatures.findIndex(s => s.role === role || (role === 'Preparer' && s.role === 'Preparer'));
      if (idx !== -1) {
          const newSigs = [...currentRisk.signatures];
          newSigs[idx] = {
              name: userProfile?.name || "User",
              role: newSigs[idx].role,
              date: new Date().toLocaleDateString(),
              status: "Signed"
          };
          setCurrentRisk(prev => ({ ...prev, signatures: newSigs }));
      }
  };

  // --- PDF Export with QR & Barcode ---
  const generatePDF = () => {
      const doc = new jsPDF('l', 'mm', 'a4'); // Landscape

      // Header & Barcode
      doc.setFontSize(18);
      doc.text("ISO 31000 Risk Assessment Report", 14, 20);
      doc.setFontSize(10);
      doc.text(`Organization: ${contextRef.current.organization}`, 14, 28);
      doc.text(`Generated: ${new Date().toLocaleString()}`, 14, 34);

      // QR Code (using API for simplicity without extra heavy libs)
      const qrData = encodeURIComponent(`RiskReport-${contextRef.current.organization}-${new Date().toISOString()}`);
      const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${qrData}`;
      doc.addImage(qrUrl, "PNG", 250, 10, 30, 30);
      doc.text("Scan for Digital Evidence", 250, 45);

      // Table
      const headers = [[
        "Risk No", "Title", "Category", "Inherent Score", 
        "Existing Controls", "Residual Score", "Treatment", 
        "Owner", "Status"
      ]];

      const data = riskRegisterRef.current.map(r => [
          r.risk_no, r.risk_title, r.risk_category, r.inherent_score,
          r.existing_controls, r.residual_score, r.treatment_option,
          r.risk_owner, r.status
      ]);

      autoTable(doc, {
          startY: 50,
          head: headers,
          body: data,
          theme: 'grid',
          headStyles: { fillColor: [16, 185, 129] },
          styles: { fontSize: 8 }
      });

      // Workflow Signatures Section
      const finalY = (doc as any).lastAutoTable.finalY + 10;
      doc.text("Digital Signatures & Approvals:", 14, finalY);

      let sigY = finalY + 10;
      riskRegisterRef.current.forEach(r => {
          if(sigY > 180) { doc.addPage(); sigY=20; }
          const sigText = `Risk ${r.risk_no}: ` + r.signatures.map(s => `${s.role}: ${s.status === 'Signed' ? s.name + ' (Signed)' : 'Pending'}`).join(' | ');
          doc.text(sigText, 14, sigY);
          sigY += 6;
      });

      doc.save(`Risk_Assessment_Signed.pdf`);
  };

  // --- Live API ---
  const toggleLiveConnection = async () => {
    if (isLiveConnected || isLiveConnecting) {
      setIsLiveConnected(false); setIsLiveConnecting(false); setActiveField(null);
      if (liveSessionRef.current) liveSessionRef.current = null;
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioContextRef.current) audioContextRef.current.close();
      if (processorRef.current) processorRef.current.disconnect();
      return;
    }

    setIsLiveConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const source = inputCtx.createMediaStreamSource(stream);
      const processor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = processor;
      source.connect(processor);
      processor.connect(inputCtx.destination);
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      // Live Tools
      const tools = [
        { name: "set_focus_field", parameters: { type: Type.OBJECT, properties: { field_id: { type: Type.STRING } }, required: ["field_id"] } },
        { name: "update_field", parameters: { type: Type.OBJECT, properties: { field: { type: Type.STRING }, value: { type: Type.STRING } }, required: ["field", "value"] } },
        { name: "save_risk", parameters: { type: Type.OBJECT, properties: {} } }
      ];

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: `You are a Virtual GRC Consultant.
          Process: 
          1. Risk Identification (Title, Cause, Owner, Inherent Risk).
          2. Analysis (Controls, Effectiveness, Residual Risk).
          3. Treatment (Plan, Responsibility).
          4. Monitoring (Dates, Acceptance).

          CRITICAL: Before asking about a field, you MUST call 'set_focus_field' with the EXACT HTML ID of that input (e.g. 'risk_title', 'risk_cause', 'inherent_likelihood').
          `,
          tools: [{ functionDeclarations: tools as FunctionDeclaration[] }],
        },
        callbacks: {
          onopen: () => { setIsLiveConnected(true); setIsLiveConnecting(false); },
          onmessage: async (msg: LiveServerMessage) => {
             if (msg.toolCall) {
                 for (const fc of msg.toolCall.functionCalls) {
                     const args = fc.args as any;
                     let result = { status: 'ok' };
                     if (fc.name === 'set_focus_field') setActiveField(args.field_id);
                     if (fc.name === 'update_field') {
                        setCurrentRisk(prev => ({...prev, [args.field]: args.value}));
                        result = { message: `Updated ${args.field}` };
                     }
                     if (fc.name === 'save_risk') {
                         saveRisk();
                         result = { message: "Saved" };
                     }
                     sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result } } }));
                 }
             }
             if (msg.serverContent?.modelTurn?.parts?.[0]?.inlineData) {
                 const audio = await decodeAudioData(decode(msg.serverContent.modelTurn.parts[0].inlineData.data), audioContextRef.current!, 24000, 1);
                 const source = audioContextRef.current!.createBufferSource();
                 source.buffer = audio;
                 source.connect(audioContextRef.current!.destination);
                 source.start();
             }
          }
        }
      });

      processor.onaudioprocess = (e) => {
        const blob = createBlob(e.inputBuffer.getChannelData(0));
        sessionPromise.then(s => s.sendRealtimeInput({ media: blob }));
      };
      liveSessionRef.current = {};
    } catch (e) { setIsLiveConnecting(false); }
  };

  const getFieldClass = (id: string) => {
      const base = "w-full bg-slate-950 border border-slate-700 rounded p-2 text-xs focus:border-emerald-500 outline-none transition-all duration-500";
      return activeField === id ? `${base} ring-2 ring-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.6)] border-amber-500 z-10 relative` : base;
  };

  return (
    <div className="max-w-[1400px] mx-auto px-4 py-6 space-y-6 pb-24 text-slate-200">
      {showAuthModal && <AuthModal onClose={() => setShowAuthModal(false)} />}

      {/* Header */}
      <header className="flex justify-between items-center bg-slate-900 p-4 rounded-xl border border-slate-800">
          <div>
            <h1 className="text-2xl font-bold text-white">ISO 31000 Risk Assessment</h1>
            <p className="text-xs text-slate-400">Virtual Consultant • Digital Signatures • Tracking</p>
          </div>
          <div className="flex gap-2 items-center">
            {user ? (
               <div className="flex items-center gap-3">
                   <div className="text-right">
                       <div className="text-xs font-bold text-emerald-400">{userProfile?.name}</div>
                       <div className="text-[10px] text-slate-500">Authorized User</div>
                   </div>
                   <button onClick={logout} className="px-3 py-1 bg-slate-800 text-xs rounded border border-slate-700">Sign Out</button>
               </div>
            ) : <button onClick={openAuthModal} className="px-3 py-1 bg-sky-600 text-xs rounded">Sign In</button>}
          </div>
      </header>

      {/* Main Content */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* Left: Risk Form (8 cols) */}
        <div className="lg:col-span-8 space-y-6">

            {/* Phase 1: Identification */}
            <section id="form-section" className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                <div className="bg-red-900/30 text-red-200 px-3 py-1 rounded text-sm font-bold mb-4 border-l-4 border-red-500">1. Risk Identification</div>
                <div className="grid grid-cols-12 gap-3">
                    <div className="col-span-2">
                        <label className="text-[10px] uppercase text-slate-500">Risk No</label>
                        <input id="risk_no" className={getFieldClass("risk_no")} value={currentRisk.risk_no} onChange={e => handleRiskChange('risk_no', e.target.value)} placeholder="#" />
                    </div>
                    <div className="col-span-5">
                        <label className="text-[10px] uppercase text-slate-500">1. Risk Title</label>
                        <input id="risk_title" className={getFieldClass("risk_title")} value={currentRisk.risk_title} onChange={e => handleRiskChange('risk_title', e.target.value)} />
                    </div>
                    <div className="col-span-5">
                        <label className="text-[10px] uppercase text-slate-500">4. Risk Category</label>
                        <select id="risk_category" className={getFieldClass("risk_category")} value={currentRisk.risk_category} onChange={e => handleRiskChange('risk_category', e.target.value)}>
                            <option value="">Select Category</option>
                            <option>Strategic</option><option>Operational</option><option>Financial</option><option>Cybersecurity</option><option>Compliance</option>
                        </select>
                    </div>
                    <div className="col-span-12">
                         <label className="text-[10px] uppercase text-slate-500">2. Identified Risk (Description)</label>
                         <textarea id="risk_description" rows={2} className={getFieldClass("risk_description")} value={currentRisk.risk_description} onChange={e => handleRiskChange('risk_description', e.target.value)} />
                    </div>
                    <div className="col-span-6">
                         <label className="text-[10px] uppercase text-slate-500">3. Potential Cause</label>
                         <textarea id="risk_cause" rows={2} className={getFieldClass("risk_cause")} value={currentRisk.risk_cause} onChange={e => handleRiskChange('risk_cause', e.target.value)} />
                    </div>
                    <div className="col-span-6">
                         <label className="text-[10px] uppercase text-slate-500">5. Risk Owner</label>
                         <input id="risk_owner" className={getFieldClass("risk_owner")} value={currentRisk.risk_owner} onChange={e => handleRiskChange('risk_owner', e.target.value)} />
                    </div>
                    <div className="col-span-4 bg-slate-950 p-2 rounded border border-slate-800">
                        <label className="text-[10px] uppercase text-slate-500 block mb-1">6. Likelihood</label>
                        <input type="number" id="inherent_likelihood" className={getFieldClass("inherent_likelihood")} value={currentRisk.inherent_likelihood} onChange={e => handleRiskChange('inherent_likelihood', Number(e.target.value))} />
                    </div>
                    <div className="col-span-4 bg-slate-950 p-2 rounded border border-slate-800">
                        <label className="text-[10px] uppercase text-slate-500 block mb-1">7. Impact</label>
                        <input type="number" id="inherent_impact" className={getFieldClass("inherent_impact")} value={currentRisk.inherent_impact} onChange={e => handleRiskChange('inherent_impact', Number(e.target.value))} />
                    </div>
                    <div className="col-span-4 bg-slate-950 p-2 rounded border border-slate-800">
                        <label className="text-[10px] uppercase text-slate-500 block mb-1">8. Inherent Risk</label>
                        <div className="text-xl font-bold text-center text-red-400">{currentRisk.inherent_score}</div>
                    </div>
                </div>
            </section>

            {/* Phase 2: Analysis */}
            <section className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                <div className="bg-emerald-900/30 text-emerald-200 px-3 py-1 rounded text-sm font-bold mb-4 border-l-4 border-emerald-500">2. Risk Analysis</div>
                <div className="grid grid-cols-12 gap-3">
                    <div className="col-span-6">
                        <label className="text-[10px] uppercase text-slate-500">9. Existing Controls</label>
                        <textarea id="existing_controls" rows={2} className={getFieldClass("existing_controls")} value={currentRisk.existing_controls} onChange={e => handleRiskChange('existing_controls', e.target.value)} />
                    </div>
                    <div className="col-span-6">
                         <label className="text-[10px] uppercase text-slate-500">10. Control Assessment</label>
                         <select id="control_effectiveness" className={getFieldClass("control_effectiveness")} value={currentRisk.control_effectiveness} onChange={e => handleRiskChange('control_effectiveness', e.target.value)}>
                            <option>Strong</option><option>Adequate</option><option>Weak</option><option>Non-Existent</option>
                         </select>
                    </div>
                    <div className="col-span-4 bg-slate-950 p-2 rounded border border-slate-800">
                        <label className="text-[10px] uppercase text-slate-500 block mb-1">11. Residual Likelihood</label>
                        <input type="number" id="residual_likelihood" className={getFieldClass("residual_likelihood")} value={currentRisk.residual_likelihood} onChange={e => handleRiskChange('residual_likelihood', Number(e.target.value))} />
                    </div>
                    <div className="col-span-4 bg-slate-950 p-2 rounded border border-slate-800">
                        <label className="text-[10px] uppercase text-slate-500 block mb-1">12. Residual Impact</label>
                        <input type="number" id="residual_impact" className={getFieldClass("residual_impact")} value={currentRisk.residual_impact} onChange={e => handleRiskChange('residual_impact', Number(e.target.value))} />
                    </div>
                    <div className="col-span-4 bg-slate-950 p-2 rounded border border-slate-800">
                        <label className="text-[10px] uppercase text-slate-500 block mb-1">13. Residual Risk</label>
                        <div className="text-xl font-bold text-center text-emerald-400">{currentRisk.residual_score}</div>
                    </div>
                </div>
            </section>

            {/* Phase 3: Treatment */}
            <section className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                <div className="bg-yellow-900/30 text-yellow-200 px-3 py-1 rounded text-sm font-bold mb-4 border-l-4 border-yellow-500">3. Risk Treatment / Action Plan</div>
                 <div className="grid grid-cols-12 gap-3">
                    <div className="col-span-4">
                        <label className="text-[10px] uppercase text-slate-500">14. Treatment Option</label>
                         <select id="treatment_option" className={getFieldClass("treatment_option")} value={currentRisk.treatment_option} onChange={e => handleRiskChange('treatment_option', e.target.value)}>
                            <option>Mitigate</option><option>Accept</option><option>Transfer</option><option>Avoid</option>
                         </select>
                    </div>
                    <div className="col-span-8">
                         <label className="text-[10px] uppercase text-slate-500">16. Responsibility (Assign Owner)</label>
                         <input id="responsibility" className={getFieldClass("responsibility")} value={currentRisk.responsibility} onChange={e => handleRiskChange('responsibility', e.target.value)} />
                    </div>
                    <div className="col-span-12">
                         <label className="text-[10px] uppercase text-slate-500">15. Mitigate Action / Plan</label>
                         <textarea id="mitigation_actions" rows={2} className={getFieldClass("mitigation_actions")} value={currentRisk.mitigation_actions} onChange={e => handleRiskChange('mitigation_actions', e.target.value)} />
                    </div>
                 </div>
            </section>

             {/* Phase 4: Monitoring */}
            <section className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                <div className="bg-blue-900/30 text-blue-200 px-3 py-1 rounded text-sm font-bold mb-4 border-l-4 border-blue-500">4. Monitoring & Review</div>
                <div className="grid grid-cols-12 gap-3">
                    <div className="col-span-4">
                        <label className="text-[10px] uppercase text-slate-500">17. By When</label>
                        <input type="date" id="due_date" className={getFieldClass("due_date")} value={currentRisk.due_date} onChange={e => handleRiskChange('due_date', e.target.value)} />
                    </div>
                    <div className="col-span-4">
                         <label className="text-[10px] uppercase text-slate-500">19. Approved By</label>
                         <input id="acceptance_approved_by" className={getFieldClass("acceptance_approved_by")} value={currentRisk.acceptance_approved_by} onChange={e => handleRiskChange('acceptance_approved_by', e.target.value)} />
                    </div>
                     <div className="col-span-4">
                         <label className="text-[10px] uppercase text-slate-500">20. Remarks</label>
                         <input id="remarks" className={getFieldClass("remarks")} value={currentRisk.remarks} onChange={e => handleRiskChange('remarks', e.target.value)} />
                    </div>
                     <div className="col-span-12">
                         <label className="text-[10px] uppercase text-slate-500">18. Acceptance Criteria</label>
                         <textarea id="acceptance_criteria" rows={2} className={getFieldClass("acceptance_criteria")} value={currentRisk.acceptance_criteria} onChange={e => handleRiskChange('acceptance_criteria', e.target.value)} />
                    </div>
                </div>
            </section>

             <div className="flex justify-end gap-2">
                 <button onClick={clearForm} className="px-4 py-2 bg-slate-800 text-slate-400 rounded hover:bg-slate-700">Clear</button>
                 <button onClick={saveRisk} className="px-6 py-2 bg-emerald-600 text-white rounded font-bold hover:bg-emerald-500">Save Risk</button>
             </div>
        </div>

        {/* Right: Workflow & Register (4 cols) */}
        <div className="lg:col-span-4 space-y-6">

            {/* Workflow & Digital Signatures */}
            <div className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                <h3 className="font-bold text-sm mb-4 border-b border-slate-700 pb-2">Digital Workflow & Approvals</h3>
                <div className="space-y-4">
                    {currentRisk.signatures.map((sig, idx) => (
                        <div key={idx} className="flex items-center justify-between text-xs bg-slate-950 p-2 rounded border border-slate-800">
                            <div>
                                <div className="font-bold text-slate-300">{sig.role}</div>
                                <div className="text-[10px] text-slate-500">{sig.status === 'Signed' ? `${sig.name} • ${sig.date}` : "Pending Signature"}</div>
                            </div>
                            <div className={`w-2 h-2 rounded-full ${sig.status === 'Signed' ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.8)]' : 'bg-slate-700'}`}></div>
                        </div>
                    ))}
                </div>

                <div className="mt-6 space-y-2">
                    <button onClick={performVirtualAudit} className="w-full py-2 bg-purple-900/40 border border-purple-500/30 text-purple-300 text-xs rounded hover:bg-purple-900/60 flex items-center justify-center gap-2">
                        <span>🤖</span> Virtual Auditor Review
                    </button>
                    <button onClick={() => digitalSign('Preparer')} className="w-full py-2 bg-slate-800 text-slate-300 text-xs rounded hover:bg-slate-700">
                        Sign as Preparer
                    </button>
                     <button onClick={() => digitalSign('CIO')} className="w-full py-2 bg-slate-800 text-slate-300 text-xs rounded hover:bg-slate-700">
                        Sign as CIO
                    </button>
                </div>

                <div className="mt-4 pt-4 border-t border-slate-800">
                     <h4 className="text-[10px] uppercase text-slate-500 mb-2">Evidence Upload</h4>
                     <div className="bg-slate-950 p-3 rounded border border-slate-800 border-dashed text-center">
                         <span className="text-xl">📎</span>
                         <p className="text-[10px] text-slate-500 mt-1">Upload Compliance Evidence</p>
                     </div>
                </div>
            </div>

            {/* Quick Actions */}
             <div className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                 <h3 className="font-bold text-sm mb-4">Actions</h3>
                 <button onClick={generatePDF} className="w-full py-2 mb-2 bg-red-900/20 text-red-400 border border-red-900/30 rounded hover:bg-red-900/40 text-xs">
                     Generate PDF (Signed & QR)
                 </button>
                 <button onClick={() => setActiveTab('dashboard')} className="w-full py-2 bg-sky-900/20 text-sky-400 border border-sky-900/30 rounded hover:bg-sky-900/40 text-xs">
                     View Dashboard
                 </button>
             </div>

             {/* Mini Register */}
             <div className="bg-slate-900 border border-slate-800 rounded-xl p-4 h-[400px] overflow-hidden flex flex-col">
                 <h3 className="font-bold text-sm mb-2">Recent Risks</h3>
                 <div className="overflow-y-auto flex-1 space-y-2 pr-1">
                     {riskRegister.map(r => (
                         <div key={r.id} onClick={() => editRiskObj(r)} className={`p-2 rounded cursor-pointer border text-xs ${currentRisk.id === r.id ? 'bg-slate-800 border-emerald-500' : 'bg-slate-950 border-slate-800 hover:border-slate-600'}`}>
                             <div className="flex justify-between font-bold mb-1">
                                 <span>{r.risk_no}</span>
                                 <span className={r.status === 'Approved' ? 'text-emerald-400' : 'text-amber-400'}>{r.status}</span>
                             </div>
                             <div className="truncate text-slate-400">{r.risk_title}</div>
                         </div>
                     ))}
                     {riskRegister.length === 0 && <div className="text-center text-xs text-slate-600 mt-10">No risks yet</div>}
                 </div>
             </div>
        </div>

      </div>

       {/* Floating Live Button */}
      <div className="fixed bottom-6 right-6 flex flex-col items-end gap-2 z-50">
        <div className={`transition-all duration-300 origin-bottom-right bg-slate-800 border border-slate-700 p-3 rounded-lg shadow-xl mb-2 max-w-xs text-xs text-slate-300 ${isLiveConnected ? 'opacity-100 scale-100' : 'opacity-0 scale-90 pointer-events-none'}`}>
          <p className="font-semibold text-sky-400 mb-1">Virtual Consultant Active</p>
          <p>I am tracking your fields. Speak to fill them.</p>
        </div>
        <button
          onClick={toggleLiveConnection}
          disabled={isLiveConnecting}
          className={`h-14 w-14 rounded-full shadow-2xl flex items-center justify-center transition-all transform hover:scale-105 ${isLiveConnected ? "bg-red-500 hover:bg-red-600 animate-pulse" : "bg-sky-500 hover:bg-sky-600"}`}
        >
          {isLiveConnecting ? <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <span className="text-2xl">{isLiveConnected ? "■" : "🎙️"}</span>}
        </button>
      </div>

    </div>
  );
};

const root = createRoot(document.getElementById("root")!);
