const AuthModal = ({ onClose }: { onClose: () => void }) => {
  const [view, setView] = useState<'login' | 'register' | 'verify'>('login');
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [verificationEmail, setVerificationEmail] = useState("");

  // Form State
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [repeatPassword, setRepeatPassword] = useState("");
  const [name, setName] = useState("");
  const [photoFile, setPhotoFile] = useState<File | null>(null);

  const resetForm = () => {
    setError("");
    setEmail("");
    setPassword("");
    setRepeatPassword("");
    setName("");
    setPhotoFile(null);
  };

  const switchToRegister = () => {
    setView('register');
    resetForm();
  };

  const switchToLogin = () => {
    setView('login');
    resetForm();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setPhotoFile(e.target.files[0]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      if (view === 'register') {
        if (password !== repeatPassword) {
          throw new Error("Passwords do not match.");
        }
        if (!name.trim()) {
           throw new Error("Name is required.");
        }

        let photoURL = "";
        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        if (photoFile) {
          const fileRef = ref(storage, `profile_photos/${user.uid}/${photoFile.name}`);
          await uploadBytes(fileRef, photoFile);
          photoURL = await getDownloadURL(fileRef);
        }

        await updateProfile(user, {
          displayName: name,
          photoURL: photoURL || "https://via.placeholder.com/150"
        });

        await sendEmailVerification(user);
        setVerificationEmail(user.email || email);
        await signOut(auth);
        setView('verify');

      } else {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        if (!user.emailVerified) {
            setVerificationEmail(user.email || email);
            await signOut(auth); 
            setView('verify');
        } else {
            onClose();
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      if (err.code === "auth/invalid-credential" || err.code === "auth/wrong-password" || err.code === "auth/user-not-found") {
        setError("Password or Email Incorrect");
      } else if (err.code === "auth/email-already-in-use") {
        setError("User already exists. Sign in?");
      } else {
        setError(err.message || "Authentication failed");
      }
    } finally {
      setLoading(false);
    }
  };

  if (view === 'verify') {
      return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
            <div className="w-full max-w-md bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
                <div className="bg-slate-800/50 p-6 border-b border-slate-700 text-center">
                    <div className="text-4xl mb-4">✉️</div>
                    <h2 className="text-xl font-bold text-white">Verify your Email</h2>
                </div>
                <div className="p-8 text-center space-y-6">
                    <p className="text-slate-300">
                        We have sent you a verification email to <span className="text-sky-400 font-semibold">{verificationEmail}</span>.
                    </p>
                    <p className="text-slate-400 text-sm">
                        Please verify it and log in to access the dashboard.
                    </p>
                    <button onClick={switchToLogin} className="w-full py-2.5 rounded-lg bg-emerald-600 hover:bg-emerald-500 text-white font-semibold text-sm transition-all active:scale-[0.98]">
                        Log In
                    </button>
                </div>
            </div>
        </div>
      );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
      <div className="w-full max-w-md bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="bg-slate-800/50 p-6 border-b border-slate-700">
          <h2 className="text-xl font-bold text-white text-center">{view === 'register' ? "Create Account" : "Welcome Back"}</h2>
          <p className="text-slate-400 text-xs text-center mt-1">ISO 31000 Risk Assessment Tool</p>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {error && (
            <div className={`p-3 rounded-lg text-xs font-medium ${error.includes("Sign in?") ? "bg-amber-500/10 text-amber-400 border border-amber-500/20" : "bg-red-500/10 text-red-400 border border-red-500/20"}`}>
              {error}
              {error.includes("Sign in?") && <button type="button" onClick={switchToLogin} className="underline ml-2 hover:text-white">Go to Login</button>}
            </div>
          )}
          {view === 'register' && (
            <div className="space-y-3 animate-in slide-in-from-top-2 duration-300">
              <div className="flex flex-col items-center justify-center gap-2 mb-4">
                 <div className="w-20 h-20 rounded-full bg-slate-800 border-2 border-dashed border-slate-600 flex items-center justify-center overflow-hidden">
                    {photoFile ? <img src={URL.createObjectURL(photoFile)} alt="Preview" className="w-full h-full object-cover" /> : <span className="text-2xl text-slate-600">📷</span>}
                 </div>
                 <label className="cursor-pointer text-xs text-sky-400 hover:text-sky-300">
                    <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
                    {photoFile ? "Change Photo" : "Upload Photo"}
                 </label>
              </div>
              <div>
                <label className="block text-xs text-slate-400 mb-1">Full Name</label>
                <input type="text" required className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:border-sky-500 outline-none" placeholder="John Doe" value={name} onChange={(e) => setName(e.target.value)} />
              </div>
            </div>
          )}
          <div>
            <label className="block text-xs text-slate-400 mb-1">Email Address</label>
            <input type="email" required className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:border-sky-500 outline-none" placeholder="name@company.com" value={email} onChange={(e) => setEmail(e.target.value)} />
          </div>
          <div>
            <label className="block text-xs text-slate-400 mb-1">Password</label>
            <input type="password" required minLength={6} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:border-sky-500 outline-none" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} />
          </div>
          {view === 'register' && (
             <div className="animate-in slide-in-from-top-2 duration-300">
              <label className="block text-xs text-slate-400 mb-1">Repeat Password</label>
              <input type="password" required minLength={6} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:border-sky-500 outline-none" placeholder="••••••••" value={repeatPassword} onChange={(e) => setRepeatPassword(e.target.value)} />
            </div>
          )}
          <button type="submit" disabled={loading} className="w-full py-2.5 rounded-lg bg-sky-600 hover:bg-sky-500 text-white font-semibold text-sm transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed mt-2">
            {loading ? "Processing..." : (view === 'register' ? "Register" : "Sign In")}
          </button>
        </form>
        <div className="bg-slate-800/50 p-4 border-t border-slate-700 text-center">
          <p className="text-xs text-slate-400">
            {view === 'register' ? "Already have an account?" : "Don't have an account?"}
