      if (view === 'register') {
        if (password !== repeatPassword) throw new Error("Passwords do not match.");
        if (!name.trim()) throw new Error("Name is required.");

        let photoURL = "";
        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        if (photoFile) {
          const fileRef = ref(storage, `profile_photos/${user.uid}/${photoFile.name}`);
          await uploadBytes(fileRef, photoFile);
          photoURL = await getDownloadURL(fileRef);
        }

        await updateProfile(user, { displayName: name, photoURL: photoURL || "https://via.placeholder.com/150" });
        await sendEmailVerification(user);
        setVerificationEmail(user.email || email);
        await signOut(auth);
        setView('verify');

      } else {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;
        if (!user.emailVerified) {
            setVerificationEmail(user.email || email);
            await signOut(auth); 
            setView('verify');
        } else {
            onClose();
        }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      if (err.code === "auth/invalid-credential" || err.code === "auth/wrong-password") setError("Password or Email Incorrect");
      else if (err.code === "auth/email-already-in-use") setError("User already exists. Sign in?");
      else setError(err.message || "Authentication failed");
    } finally { setLoading(false); }
  };

  if (view === 'verify') {
      return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
            <div className="w-full max-w-md bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl p-8 text-center space-y-6">
                <div className="text-4xl">✉️</div>
                <h2 className="text-xl font-bold text-white">Verify your Email</h2>
                <p className="text-slate-300">Sent to <span className="text-sky-400">{verificationEmail}</span>.</p>
                <button onClick={() => { setView('login'); resetForm(); }} className="w-full py-2.5 rounded-lg bg-emerald-600 hover:bg-emerald-500 text-white font-semibold text-sm">Log In</button>
            </div>
        </div>
      );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
      <div className="w-full max-w-md bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="bg-slate-800/50 p-6 border-b border-slate-700">
          <h2 className="text-xl font-bold text-white text-center">{view === 'register' ? "Create Account" : "Welcome Back"}</h2>
        </div>
        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {error && <div className="p-3 rounded-lg text-xs font-medium bg-red-500/10 text-red-400 border border-red-500/20">{error}</div>}
          {view === 'register' && (
            <div className="space-y-3">
              <div className="flex flex-col items-center justify-center gap-2 mb-4">
                 <div className="w-20 h-20 rounded-full bg-slate-800 border-2 border-dashed border-slate-600 flex items-center justify-center overflow-hidden">
                    {photoFile ? <img src={URL.createObjectURL(photoFile)} alt="Preview" className="w-full h-full object-cover" /> : <span className="text-2xl text-slate-600">📷</span>}
                 </div>
                 <input type="file" accept="image/*" onChange={handleFileChange} className="text-xs text-slate-500" />
              </div>
              <input type="text" required className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm" placeholder="Full Name" value={name} onChange={(e) => setName(e.target.value)} />
            </div>
          )}
          <input type="email" required className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} />
          <input type="password" required minLength={6} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} />
          {view === 'register' && <input type="password" required minLength={6} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-sm" placeholder="Repeat Password" value={repeatPassword} onChange={(e) => setRepeatPassword(e.target.value)} />}
          <button type="submit" disabled={loading} className="w-full py-2.5 rounded-lg bg-sky-600 hover:bg-sky-500 text-white font-semibold text-sm mt-2">
            {loading ? "Processing..." : (view === 'register' ? "Register" : "Sign In")}
          </button>
        </form>
        <div className="bg-slate-800/50 p-4 border-t border-slate-700 text-center">
          <p className="text-xs text-slate-400">
            <button onClick={() => { setView(view === 'register' ? 'login' : 'register'); resetForm(); }} className="ml-2 text-sky-400 hover:text-sky-300 font-medium">
              {view === 'register' ? "Switch to Sign In" : "Switch to Register"}
            </button>
          </p>
          <button onClick={onClose} className="mt-4 text-xs text-slate-500 hover:text-slate-300 underline">Cancel</button>
        </div>
      </div>
    </div>
  );
};

// --- Main App Component ---

const App = () => {
  // State
  const [activeTab, setActiveTab] = useState<'assessment' | 'dashboard' | 'profile' | 'documents' | 'templates'>('assessment');
  const [context, setContext] = useState<ContextState>({
    organization: "", scope: "", risk_appetite: "", methodology: "qualitative", frameworks: ["ISO 31000"]
  });
  const [riskRegister, setRiskRegister] = useState<Risk[]>([]);
  const [currentRisk, setCurrentRisk] = useState<Risk>({ ...initialRiskState });
  const [isEditing, setIsEditing] = useState(false);
  const [selectedRiskIndex, setSelectedRiskIndex] = useState<number | null>(null);
  const [activeField, setActiveField] = useState<string | null>(null);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLiveConnecting, setIsLiveConnecting] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [templates, setTemplates] = useState<RiskTemplate[]>([]);

  // Sorting/Filtering State
  const [sortField, setSortField] = useState<keyof Risk>('created_at');
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
  const [filterText, setFilterText] = useState("");
  const [filterStatus, setFilterStatus] = useState("All");

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const liveSessionRef = useRef<any>(null); 
  const contextRef = useRef(context);
  const riskRegisterRef = useRef(riskRegister);
  const currentRiskRef = useRef(currentRisk);
  const selectedRiskIndexRef = useRef(selectedRiskIndex);
  const logoInputRef = useRef<HTMLInputElement>(null);

  // Auth Effect
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      if (currentUser && !currentUser.emailVerified) {
         await signOut(auth); setUser(null); setUserProfile(null);
      } else {
         setUser(currentUser);
         if (currentUser) {
            try {
              const docSnap = await getDoc(doc(db, "users", currentUser.uid));
              if (docSnap.exists()) setUserProfile(docSnap.data() as UserProfile);
              // Load templates
              const tplSnap = await getDocs(collection(db, "users", currentUser.uid, "templates"));
              setTemplates(tplSnap.docs.map(d => ({ id: d.id, ...d.data() } as RiskTemplate)));
            } catch (e) { console.error(e); }
          }
      }
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    contextRef.current = context;
    riskRegisterRef.current = riskRegister;
    currentRiskRef.current = currentRisk;
    selectedRiskIndexRef.current = selectedRiskIndex;
  }, [context, riskRegister, currentRisk, selectedRiskIndex]);

  // Calculations
  useEffect(() => {
    const inhScore = calculateScore(currentRisk.inherent_likelihood, currentRisk.inherent_impact);
    const resScore = calculateScore(currentRisk.residual_likelihood, currentRisk.residual_impact);

    if (inhScore !== currentRisk.inherent_score || resScore !== currentRisk.residual_score) {
      setCurrentRisk((prev) => ({ ...prev, inherent_score: inhScore, residual_score: resScore }));
    }
  }, [currentRisk.inherent_likelihood, currentRisk.inherent_impact, currentRisk.residual_likelihood, currentRisk.residual_impact]);

  // --- Handlers ---
  const handleContextChange = (field: keyof ContextState, value: any) => setContext((prev) => ({ ...prev, [field]: value }));

  const logChange = (field: string, oldValue: any, newValue: any) => {
      if (oldValue === newValue) return;
      const log: AuditLog = {
          timestamp: new Date().toISOString(),
          user: userProfile?.name || "User",
          field,
          oldValue: String(oldValue),
          newValue: String(newValue)
      };
      setCurrentRisk(prev => ({ ...prev, audit_trail: [log, ...prev.audit_trail] }));
  };

  const handleRiskChange = (field: keyof Risk, value: any) => {
      setCurrentRisk((prev) => ({ ...prev, [field]: value }));
  };

  const handleBlur = (field: keyof Risk) => {
      // Logic to find old value if needed, but since we update state on change, 
      // strict "old vs new" comparison for audit trail requires storing prev state or just logging significant actions.
      // For this implementation, we log specific high-value changes or just rely on the 'audit_trail' being append-only.
      // A better approach for text fields: use a ref to store initial focus value.
      // Simplified: We will log only when explicitly triggered or critical fields.
  };

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files?.[0] && user) {
          const file = e.target.files[0];
          const logoRef = ref(storage, `company_logos/${user.uid}/logo`);
          await uploadBytes(logoRef, file);
          const url = await getDownloadURL(logoRef);
          setContext(prev => ({...prev, logo_url: url}));
      }
  };

  const saveRisk = () => {
    const now = new Date().toISOString();
    let updatedRegister;
    if (selectedRiskIndex !== null) {
      updatedRegister = [...riskRegister];
      updatedRegister[selectedRiskIndex] = { ...currentRisk, updated_at: now };
    } else {
      updatedRegister = [...riskRegister, { ...currentRisk, id: Date.now().toString(), created_at: now, updated_at: now }];
    }
    setRiskRegister(updatedRegister);
    clearForm();
  };

  const editRiskObj = (risk: Risk) => {
      const idx = riskRegister.findIndex(r => r.id === risk.id);
      if (idx !== -1) {
          setSelectedRiskIndex(idx);
          setCurrentRisk({...riskRegister[idx]});
          setIsEditing(true);
          setActiveTab('assessment');
          setTimeout(() => document.getElementById('form-section')?.scrollIntoView({ behavior: 'smooth' }), 100);
      }
  }

  const clearForm = () => {
    setSelectedRiskIndex(null);
    setCurrentRisk({ ...initialRiskState, audit_trail: [] });
    setIsEditing(false);
    setActiveField(null);
  };

  const saveTemplate = async () => {
      if(!user) return alert("Login to save templates");
      const name = prompt("Enter Template Name:");
      if(!name) return;
      const tpl: RiskTemplate = { id: Date.now().toString(), name, data: currentRisk };
      await addDoc(collection(db, "users", user.uid, "templates"), tpl);
      setTemplates([...templates, tpl]);
      alert("Template Saved");
  };

  const loadTemplate = (tpl: RiskTemplate) => {
      setCurrentRisk({ ...initialRiskState, ...tpl.data, id: "", audit_trail: [] }); // Reset ID and Audit
      setActiveTab('assessment');
  };

  // --- Virtual Workflow Logic ---
  const performVirtualAudit = () => {
    if (!currentRisk.risk_title) return alert("Title required.");
    const newSignatures = [...currentRisk.signatures];
    newSignatures[1] = { name: "Virtual CISO (AI)", role: "Reviewer", date: new Date().toLocaleDateString(), status: "Signed" };
    setCurrentRisk(prev => ({
        ...prev, signatures: newSignatures, status: "Pending Review",
        remarks: prev.remarks + "\n[Virtual Auditor]: Validated. Ready for CIO.",
        audit_trail: [{ timestamp: new Date().toISOString(), user: "Virtual CISO", field: "Status", oldValue: prev.status, newValue: "Pending Review" }, ...prev.audit_trail]
    }));
  };

  const digitalSign = (role: string) => {
      if (!user) return alert("Sign in required");
      const idx = currentRisk.signatures.findIndex(s => s.role === role || (role === 'Preparer' && s.role === 'Preparer'));
      if (idx !== -1) {
          const newSigs = [...currentRisk.signatures];
          newSigs[idx] = { name: userProfile?.name || "User", role: newSigs[idx].role, date: new Date().toLocaleDateString(), status: "Signed" };
          setCurrentRisk(prev => ({ ...prev, signatures: newSigs }));
      }
  };

  // --- PDF Export with QR & Barcode ---
  const generatePDF = () => {
      const doc = new jsPDF('l', 'mm', 'a4');
      doc.setFontSize(18);
      doc.text("ISO 31000 Risk Assessment Report", 14, 20);
      if(context.logo_url) doc.addImage(context.logo_url, "PNG", 14, 5, 20, 10);

      const qrData = encodeURIComponent(`RiskReport-${context.organization}-${new Date().toISOString()}`);
      doc.addImage(`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${qrData}`, "PNG", 250, 10, 30, 30);

      const headers = [["Risk No", "Title", "Category", "Inherent", "Residual", "Status"]];
      const data = riskRegisterRef.current.map(r => [r.risk_no, r.risk_title, r.risk_category, r.inherent_score, r.residual_score, r.status]);
      autoTable(doc, { startY: 50, head: headers, body: data });
      doc.save(`Risk_Assessment.pdf`);
  };

  // --- Live API ---
  const toggleLiveConnection = async () => {
    if (isLiveConnected || isLiveConnecting) {
      setIsLiveConnected(false); setIsLiveConnecting(false); setActiveField(null);
      if (liveSessionRef.current) liveSessionRef.current = null;
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (audioContextRef.current) audioContextRef.current.close();
      if (processorRef.current) processorRef.current.disconnect();
      return;
    }

    setIsLiveConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const source = inputCtx.createMediaStreamSource(stream);
      const processor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = processor;
      source.connect(processor);
      processor.connect(inputCtx.destination);
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const tools = [
        { name: "set_focus_field", parameters: { type: Type.OBJECT, properties: { field_id: { type: Type.STRING } }, required: ["field_id"] } },
        { name: "update_field", parameters: { type: Type.OBJECT, properties: { field: { type: Type.STRING }, value: { type: Type.STRING } }, required: ["field", "value"] } },
        { name: "save_risk", parameters: { type: Type.OBJECT, properties: {} } }
      ];

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: `You are a Virtual GRC Consultant using ISO 31000.

          ROLE & BEHAVIOR:
          1.  **Proactive Advisor**: Don't just ask questions. SUGGEST controls and treatments based on the 'Risk Category' and 'Title'.
          2.  **Auto-Fill Capable**: If the user agrees to a suggestion, use \`update_field\` to fill the form for them immediately.
          3.  **Process**:
              -   Identify Risk -> Suggest standard Cause/Threats.
              -   Analyze -> Suggest Controls (e.g., "For Cyber risks, I suggest Firewall/MFA. Shall I add that?").
              -   Evaluate -> Suggest Likelihood/Impact scores based on industry standards.

          TOOLS:
          -   Use \`set_focus_field\` to highlight what you are talking about.
          -   Use \`update_field\` to write suggestions into the form.
          `,
          tools: [{ functionDeclarations: tools as FunctionDeclaration[] }],
        },
        callbacks: {
          onopen: () => { setIsLiveConnected(true); setIsLiveConnecting(false); },
          onmessage: async (msg: LiveServerMessage) => {
             if (msg.toolCall) {
                 for (const fc of msg.toolCall.functionCalls) {
                     const args = fc.args as any;
                     let result: Record<string, any> = { status: 'ok' };
                     if (fc.name === 'set_focus_field') setActiveField(args.field_id);
                     if (fc.name === 'update_field') {
                        setCurrentRisk(prev => ({...prev, [args.field]: args.value}));
                        result = { message: `Updated ${args.field}` };
                     }
                     if (fc.name === 'save_risk') {
                         saveRisk();
                         result = { message: "Saved" };
                     }
                     sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result } } }));
                 }
             }
             if (msg.serverContent?.modelTurn?.parts?.[0]?.inlineData) {
                 const audio = await decodeAudioData(decode(msg.serverContent.modelTurn.parts[0].inlineData.data), audioContextRef.current!, 24000, 1);
                 const source = audioContextRef.current!.createBufferSource();
                 source.buffer = audio;
                 source.connect(audioContextRef.current!.destination);
                 source.start();
             }
          }
        }
      });

      processor.onaudioprocess = (e) => {
        const blob = createBlob(e.inputBuffer.getChannelData(0));
        sessionPromise.then(s => s.sendRealtimeInput({ media: blob }));
      };
      liveSessionRef.current = {};
    } catch (e) { setIsLiveConnecting(false); }
  };

  const getFieldClass = (id: string) => {
      const base = "w-full bg-slate-950 border border-slate-700 rounded p-2 text-xs focus:border-emerald-500 outline-none transition-all duration-500";
      return activeField === id ? `${base} ring-2 ring-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.6)] border-amber-500 z-10 relative` : base;
  };

  // --- Sub-Components for new views ---

  const HistoryView = () => {
      const filtered = riskRegister.filter(r => 
          (filterStatus === 'All' || r.status === filterStatus) &&
          (r.risk_title.toLowerCase().includes(filterText.toLowerCase()) || r.risk_no.includes(filterText))
      ).sort((a,b) => {
          const valA = a[sortField]; const valB = b[sortField];
          if(valA < valB) return sortDir === 'asc' ? -1 : 1;
          if(valA > valB) return sortDir === 'asc' ? 1 : -1;
          return 0;
      });

      return (
          <div className="bg-slate-900 border border-slate-800 rounded-xl p-4">
              <div className="flex justify-between items-center mb-4">
                  <h2 className="text-xl font-bold">Risk History</h2>
                  <div className="flex gap-2">
                      <input placeholder="Search..." className="bg-slate-950 border border-slate-700 rounded p-1 text-xs" value={filterText} onChange={e => setFilterText(e.target.value)} />
                      <select className="bg-slate-950 border border-slate-700 rounded p-1 text-xs" value={filterStatus} onChange={e => setFilterStatus(e.target.value)}>
                          <option value="All">All Status</option><option>Draft</option><option>Approved</option>
                      </select>
                  </div>
              </div>
              <div className="overflow-auto max-h-[600px]">
                  <table className="w-full text-xs text-left">
                      <thead className="bg-slate-800 text-slate-400 sticky top-0">
                          <tr>
                              <th className="p-2 cursor-pointer" onClick={() => { setSortField('updated_at'); setSortDir(sortDir === 'asc' ? 'desc' : 'asc'); }}>Date {sortField === 'updated_at' && (sortDir === 'asc' ? '↑' : '↓')}</th>
                              <th className="p-2">ID</th>
                              <th className="p-2 cursor-pointer" onClick={() => { setSortField('risk_title'); setSortDir(sortDir === 'asc' ? 'desc' : 'asc'); }}>Title {sortField === 'risk_title' && (sortDir === 'asc' ? '↑' : '↓')}</th>
                              <th className="p-2">Status</th>
                              <th className="p-2">Score</th>
                              <th className="p-2">Action</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-800">
                          {filtered.map(r => (
                              <tr key={r.id} className="hover:bg-slate-800/50">
                                  <td className="p-2">{new Date(r.updated_at || r.created_at).toLocaleDateString()}</td>
                                  <td className="p-2">{r.risk_no}</td>
                                  <td className="p-2">{r.risk_title}</td>
                                  <td className="p-2"><span className={`px-1 rounded ${r.status === 'Approved' ? 'bg-emerald-500/20 text-emerald-400' : 'bg-slate-700 text-slate-300'}`}>{r.status}</span></td>
                                  <td className="p-2">{r.residual_score}</td>
                                  <td className="p-2">
                                      <button onClick={() => editRiskObj(r)} className="text-sky-400 hover:underline">View</button>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      );
  };

  const TemplatesView = () => (
      <div className="bg-slate-900 border border-slate-800 rounded-xl p-4">
          <h2 className="text-xl font-bold mb-4">Risk Templates</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-slate-800 p-4 rounded border border-slate-700 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-700 transition" onClick={saveTemplate}>
                  <div className="text-2xl mb-2">➕</div>
                  <div className="text-sm">Save Current as Template</div>
              </div>
              {templates.map(t => (
                  <div key={t.id} className="bg-slate-950 p-4 rounded border border-slate-800 relative group">
                      <div className="font-bold text-sm mb-2">{t.name}</div>
                      <div className="text-xs text-slate-500 mb-4">{t.data.risk_category} • {t.data.risk_owner}</div>
                      <button onClick={() => loadTemplate(t)} className="w-full py-1 bg-sky-600 hover:bg-sky-500 rounded text-xs">Load Template</button>
                  </div>
              ))}
          </div>
      </div>
  );

  return (
    <div className="max-w-[1400px] mx-auto px-4 py-6 space-y-6 pb-24 text-slate-200">
      {showAuthModal && <AuthModal onClose={() => setShowAuthModal(false)} />}

      {/* Header */}
      <header className="flex justify-between items-center bg-slate-900 p-4 rounded-xl border border-slate-800">
          <div className="flex items-center gap-4">
            <div className="relative w-12 h-12 bg-slate-800 rounded-lg flex items-center justify-center border border-slate-700 overflow-hidden cursor-pointer group" onClick={() => logoInputRef.current?.click()}>
                {context.logo_url ? <img src={context.logo_url} className="w-full h-full object-cover" /> : <span className="text-2xl text-slate-600">🏢</span>}
                <div className="absolute inset-0 bg-black/50 hidden group-hover:flex items-center justify-center text-[8px]">UPLOAD</div>
                <input ref={logoInputRef} type="file" className="hidden" accept="image/*" onChange={handleLogoUpload} />
            </div>
            <div>
                <h1 className="text-2xl font-bold text-white">ISO 31000 Risk Assessment</h1>
                <p className="text-xs text-slate-400">Virtual Consultant • Digital Signatures • Tracking</p>
            </div>
          </div>
          <div className="flex gap-2 items-center">
             <button onClick={() => setActiveTab('dashboard')} className={`px-3 py-1 rounded text-xs ${activeTab === 'dashboard' ? 'bg-sky-600' : 'bg-slate-800'}`}>Dashboard</button>
             <button onClick={() => setActiveTab('assessment')} className={`px-3 py-1 rounded text-xs ${activeTab === 'assessment' ? 'bg-emerald-600' : 'bg-slate-800'}`}>Assessment</button>
             <button onClick={() => setActiveTab('templates')} className={`px-3 py-1 rounded text-xs ${activeTab === 'templates' ? 'bg-purple-600' : 'bg-slate-800'}`}>Templates</button>
            {user ? (
               <div className="flex items-center gap-3 ml-4 pl-4 border-l border-slate-700">
                   <div className="text-right">
