          ["12. Residual Impact", risk.residual_impact.toString()],
          ["13. Residual Risk", risk.residual_score.toString()],
          ["14. Treatment Option", risk.treatment_option],
          ["15. Mitigation Plan", risk.mitigation_actions],
          ["16. Responsibility", risk.responsibility],
          ["17. By When", risk.due_date],
          ["18. Acceptance Criteria", risk.acceptance_criteria],
          ["19. Approved By", risk.acceptance_approved_by],
          ["20. Remarks", risk.remarks]
      ];

      autoTable(doc, {
          startY: 70,
          head: [["Field", "Value"]],
          body: data,
          theme: 'grid',
          headStyles: { fillColor: [16, 185, 129] }
      });

      // Digital Signatures
      let finalY = (doc as any).lastAutoTable.finalY + 20;
      doc.setFontSize(12);
      doc.text("Digital Signatures & Approvals", margin, finalY);
      finalY += 10;

      risk.signatures.forEach((sig, i) => {
          const x = margin + (i * 45);
          doc.setDrawColor(200);
          doc.rect(x, finalY, 40, 30);
          doc.setFontSize(8);
          doc.setTextColor(100);
          doc.text(sig.role, x + 2, finalY + 5);

          if (sig.status === 'Signed') {
              doc.setTextColor(0, 128, 0); // Green
              doc.setFontSize(9);
              doc.text("SIGNED", x + 10, finalY + 15);
              doc.setTextColor(0);
              doc.setFontSize(7);
              doc.text(sig.name, x + 2, finalY + 22);
              doc.text(sig.date, x + 2, finalY + 27);
          } else {
              doc.text("Pending...", x + 10, finalY + 15);
          }
      });

      doc.save(`RiskReport_${risk.risk_no}.pdf`);
  };

  // --- Workflow Actions ---
  const performVirtualReview = (roleName: string) => {
     // Simulates AI Validation
     const idx = currentRisk.signatures.findIndex(s => s.role === roleName);
     if (idx === -1) return;

     const newSigs = [...currentRisk.signatures];
     newSigs[idx] = { ...newSigs[idx], name: roleName === 'Virtual Auditor' ? 'AI Auditor' : 'AI CISO', date: new Date().toLocaleDateString(), status: 'Signed' };

     // If CISO signs, status becomes Approved
     const newStatus = roleName === 'Virtual CISO' ? 'Approved' : currentRisk.status;

     setCurrentRisk(p => ({ ...p, signatures: newSigs, status: newStatus as any }));
     alert(`${roleName} has successfully reviewed and validated the document.`);
  };

  const userSign = (roleIndex: number) => {
      if(!user) return setShowAuthModal(true);
      const newSigs = [...currentRisk.signatures];
      newSigs[roleIndex] = { ...newSigs[roleIndex], name: userProfile?.name || "User", date: new Date().toLocaleDateString(), status: 'Signed' };
      setCurrentRisk(p => ({ ...p, signatures: newSigs }));
  };

  // --- Live AI ---
  const toggleLive = async () => {
      if(isLiveConnected) {
          setIsLiveConnected(false);
          return;
      }
      setIsLiveConnecting(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const sessionPromise = ai.live.connect({
             model: 'gemini-2.5-flash-native-audio-preview-09-2025',
             config: {
                 responseModalities: [Modality.AUDIO],
                 speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
                 systemInstruction: `You are a Virtual GRC Consultant acting as an Auditor.
                 YOUR GOAL: Guide the user to fill the 20-field ISO 31000 form sequentially.

                 FIELDS:
                 1. Risk Identification (Fields 1-8): Risk No, Title, Category, Cause, Owner, Likelihood, Impact, Inherent Risk.
                 2. Risk Analysis (Fields 9-13): Existing Controls, Effectiveness, Residual Likelihood, Residual Impact, Residual Risk.
                 3. Treatment (Fields 14-16): Treatment Option, Mitigation Plan, Responsibility.
                 4. Monitoring (Fields 17-20): Due Date, Acceptance Criteria, Approved By, Remarks.

                 RULES:
                 1. Always use \`set_focus_field\` to highlight the field you are discussing.
                 2. Use \`update_field\` to write user answers.
                 3. If user asks to review, act as Virtual Auditor and confirm validation.
                 `,
                 tools: [{
                     functionDeclarations: [
                         { name: "set_focus_field", parameters: { type: Type.OBJECT, properties: { field: { type: Type.STRING } }, required: ["field"] } },
                         { name: "update_field", parameters: { type: Type.OBJECT, properties: { field: { type: Type.STRING }, value: { type: Type.STRING } }, required: ["field", "value"] } },
                         { name: "save_report", parameters: { type: Type.OBJECT, properties: {} } }
                     ]
                 }]
             },
             callbacks: {
                 onopen: () => { setIsLiveConnected(true); setIsLiveConnecting(false); },
                 onmessage: async (msg: LiveServerMessage) => {
                     if(msg.toolCall) {
                         for(const fc of msg.toolCall.functionCalls) {
                             const args = fc.args as any;
                             if(fc.name === 'set_focus_field') setActiveField(args.field);
                             if(fc.name === 'update_field') {
                                 const val = args.field.includes('score') || args.field.includes('likelihood') || args.field.includes('impact') ? Number(args.value) : args.value;
                                 setCurrentRisk(p => ({...p, [args.field]: val}));
                             }
                             if(fc.name === 'save_report') saveRisk();
                             sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: { ok: true } } } }));
                         }
                     }
                     if(msg.serverContent?.modelTurn?.parts?.[0]?.inlineData) {
                        const ctx = audioContextRef.current || new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
                        audioContextRef.current = ctx;
                        const buf = await decodeAudioData(decode(msg.serverContent.modelTurn.parts[0].inlineData.data), ctx, 24000, 1);
                        const src = ctx.createBufferSource();
                        src.buffer = buf;
                        src.connect(ctx.destination);
                        src.start();
                     }
                 }
             }
          });

          const stream = await navigator.mediaDevices.getUserMedia({audio: true});
          const ctx = new AudioContext({sampleRate: 16000});
          const src = ctx.createMediaStreamSource(stream);
          const proc = ctx.createScriptProcessor(4096, 1, 1);
          proc.onaudioprocess = (e) => {
              const blob = createBlob(e.inputBuffer.getChannelData(0));
              sessionPromise.then(s => s.sendRealtimeInput({ media: blob }));
          }
          src.connect(proc); proc.connect(ctx.destination);

      } catch(e) { console.error(e); setIsLiveConnecting(false); }
  };

  const getFieldClass = (id: string) => {
      const base = "w-full bg-slate-950 border border-slate-700 rounded p-2 text-xs focus:border-emerald-500 outline-none transition-all duration-300";
      return activeField === id ? `${base} ring-2 ring-amber-500 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.5)] z-10 relative` : base;
  }

  return (
    <div className="max-w-[1600px] mx-auto px-4 py-4 space-y-4 pb-24 text-slate-200 font-sans">

      {/* HEADER */}
      <header className="flex justify-between items-center bg-slate-900 p-4 rounded-xl border border-slate-800 shadow-lg">
          <div>
              <h1 className="text-xl md:text-2xl font-bold bg-gradient-to-r from-emerald-400 to-cyan-400 bg-clip-text text-transparent">ISO 31000 Risk Assessment Dashboard</h1>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest">Virtual GRC Consultant • ISO 31000 Standard</p>
          </div>
          <div className="flex items-center gap-3">
              <button onClick={() => setActiveTab('register')} className={`px-4 py-2 rounded text-xs font-semibold ${activeTab === 'register' ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}>Register</button>
              <button onClick={() => setActiveTab('documents')} className={`px-4 py-2 rounded text-xs font-semibold ${activeTab === 'documents' ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}>Documents</button>

              <div className="h-8 w-px bg-slate-700 mx-2"></div>

              <button onClick={startNewRisk} className="px-5 py-2 bg-emerald-600 hover:bg-emerald-500 text-white font-bold rounded text-xs shadow-lg shadow-emerald-900/40 transition-transform hover:scale-105 flex items-center gap-2">
                  <span>+</span> New Risk
              </button>

              <button onClick={() => user ? signOut(auth) : setShowAuthModal(true)} className="ml-2 px-3 py-2 border border-slate-700 rounded text-xs text-slate-400 hover:text-white hover:border-slate-500">
                  {user ? "Sign Out" : "Sign In"}
              </button>
          </div>
      </header>

      {/* AUTH MODAL */}
      {showAuthModal && <AuthModal onClose={() => setShowAuthModal(false)} />}

      {/* VIEW: REGISTER */}
      {activeTab === 'register' && (
          <div className="bg-slate-900 border border-slate-800 rounded-xl p-4">
               <div className="flex justify-between items-center mb-4">
                  <h2 className="font-bold text-lg">Risk Register</h2>
                  <button onClick={loadLibrary} className="text-xs text-sky-400 hover:underline">Load Sample Library</button>
              </div>
              <div className="overflow-x-auto">
                  <table className="w-full text-xs text-left text-slate-300">
                      <thead className="bg-slate-950 text-slate-500 uppercase font-bold">
