          {/* LEFT: FORM (8 Cols) */}
          <div className="lg:col-span-8 space-y-6">

              {/* 1. Identification */}
              <section className="bg-slate-900 border border-slate-800 rounded-xl p-5 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-red-500"></div>
                  <h3 className="text-sm font-bold text-red-400 mb-4 uppercase tracking-wider flex justify-between">
                      <span>1. Risk Identification</span>
