                  </h3>
                  <div className="grid grid-cols-12 gap-4">
                      <div className="col-span-3">
                          <label className="text-[10px] uppercase text-slate-500">1. Risk No</label>
                          <input id="risk_no" className={getFieldClass("risk_no")} value={currentRisk.risk_no} onChange={e => handleRiskChange('risk_no', e.target.value)} />
                      </div>
                      <div className="col-span-9">
                          <label className="text-[10px] uppercase text-slate-500">2/3. Risk Title</label>
                          <input id="risk_title" className={getFieldClass("risk_title")} value={currentRisk.risk_title} onChange={e => handleRiskChange('risk_title', e.target.value)} />
                      </div>
                      <div className="col-span-12">
                          <label className="text-[10px] uppercase text-slate-500">Context Description (Identified Risk)</label>
                          <textarea id="risk_description" rows={2} className={getFieldClass("risk_description")} value={currentRisk.risk_description} onChange={e => handleRiskChange('risk_description', e.target.value)} />
                      </div>
                      <div className="col-span-4">
