              {/* 2. Analysis */}
              <section className="bg-slate-900 border border-slate-800 rounded-xl p-5 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-emerald-500"></div>
                  <h3 className="text-sm font-bold text-emerald-400 mb-4 uppercase tracking-wider">2. Risk Analysis (Fields 9-13)</h3>
                  <div className="grid grid-cols-12 gap-4">
                      <div className="col-span-8">
                          <label className="text-[10px] uppercase text-slate-500">9. Existing Controls / Current Measures</label>
                          <textarea id="existing_controls" rows={2} className={getFieldClass("existing_controls")} value={currentRisk.existing_controls} onChange={e => handleRiskChange('existing_controls', e.target.value)} />
