                      <div className="col-span-4">
                          <label className="text-[10px] uppercase text-slate-500">10. Control Assessment</label>
                          <select id="control_effectiveness" className={getFieldClass("control_effectiveness")} value={currentRisk.control_effectiveness} onChange={e => handleRiskChange('control_effectiveness', e.target.value)}>
