                      </div>
                  </div>
              </section>

              {/* 3. Treatment */}
              <section className="bg-slate-900 border border-slate-800 rounded-xl p-5 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-yellow-500"></div>
                  <h3 className="text-sm font-bold text-yellow-400 mb-4 uppercase tracking-wider">3. Risk Treatment / Action Plan (Fields 14-16)</h3>
                  <div className="grid grid-cols-12 gap-4">
                      <div className="col-span-4">
                          <label className="text-[10px] uppercase text-slate-500">14. Treatment Option</label>
                          <select id="treatment_option" className={getFieldClass("treatment_option")} value={currentRisk.treatment_option} onChange={e => handleRiskChange('treatment_option', e.target.value)}>
                              <option>Mitigate</option><option>Accept</option><option>Transfer</option><option>Avoid</option>
                          </select>
                      </div>
                      <div className="col-span-8">
                          <label className="text-[10px] uppercase text-slate-500">15. Mitigation Action / Plan</label>
                          <textarea id="mitigation_actions" rows={2} className={getFieldClass("mitigation_actions")} value={currentRisk.mitigation_actions} onChange={e => handleRiskChange('mitigation_actions', e.target.value)} />
                      </div>
                      <div className="col-span-12">
                          <label className="text-[10px] uppercase text-slate-500">16. Responsibility (Assignee)</label>
                          <input id="responsibility" className={getFieldClass("responsibility")} value={currentRisk.responsibility} onChange={e => handleRiskChange('responsibility', e.target.value)} />
                      </div>
                  </div>
              </section>

              {/* 4. Monitoring */}
              <section className="bg-slate-900 border border-slate-800 rounded-xl p-5 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-blue-500"></div>
                  <h3 className="text-sm font-bold text-blue-400 mb-4 uppercase tracking-wider">4. Monitoring & Review (Fields 17-20)</h3>
                  <div className="grid grid-cols-12 gap-4">
                      <div className="col-span-4">
                          <label className="text-[10px] uppercase text-slate-500">17. By When (Date)</label>
                          <input type="date" id="due_date" className={getFieldClass("due_date")} value={currentRisk.due_date} onChange={e => handleRiskChange('due_date', e.target.value)} />
                      </div>
                      <div className="col-span-8">
                          <label className="text-[10px] uppercase text-slate-500">18. Risk Acceptance Criteria</label>
                          <input id="acceptance_criteria" className={getFieldClass("acceptance_criteria")} value={currentRisk.acceptance_criteria} onChange={e => handleRiskChange('acceptance_criteria', e.target.value)} />
                      </div>
                      <div className="col-span-6">
                          <label className="text-[10px] uppercase text-slate-500">19. Acceptance Approved By</label>
                          <input id="acceptance_approved_by" className={getFieldClass("acceptance_approved_by")} value={currentRisk.acceptance_approved_by} onChange={e => handleRiskChange('acceptance_approved_by', e.target.value)} />
