                  <button onClick={saveRisk} className="px-6 py-2 bg-emerald-600 hover:bg-emerald-500 text-white font-bold rounded text-sm shadow-lg">Save Risk</button>
              </div>

          </div>

          {/* RIGHT: WORKFLOW (4 Cols) */}
