const Scanner = ({ onScan, onClose }: { onScan: (result: string) => void, onClose: () => void }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const [scanning, setScanning] = useState(true);

    useEffect(() => {
        let stream: MediaStream | null = null;
        const startCamera = async () => {
            try {
                stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
                if (videoRef.current) {
                    videoRef.current.srcObject = stream;
                }
            } catch (err) {
                console.error("Camera error:", err);
                alert("Could not access camera.");
            }
        };
        startCamera();
        return () => {
            if (stream) stream.getTracks().forEach(t => t.stop());
        }
    }, []);

    const simulateScan = () => {
        setScanning(false);
        // In a real app, we would use a QR library like jsQR here on a canvas snapshot
        setTimeout(() => {
            onScan("R-LIB-01"); // Simulating finding a specific risk ID
        }, 1000);
    };

    return (
        <div className="fixed inset-0 z-[60] bg-black flex flex-col items-center justify-center p-4">
            <div className="relative w-full max-w-sm aspect-square bg-black rounded-xl overflow-hidden border-2 border-emerald-500 shadow-[0_0_30px_rgba(16,185,129,0.3)]">
                <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover opacity-80" />
                <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                    <div className="w-48 h-48 border-2 border-white/50 rounded-lg relative">
                        <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-emerald-400"></div>
                        <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-emerald-400"></div>
                        <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-emerald-400"></div>
                        <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-emerald-400"></div>
                        {scanning && <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-red-500 shadow-[0_0_10px_red] animate-pulse"></div>}
                    </div>
                </div>
            </div>
            <div className="mt-8 flex gap-4">
                <button onClick={onClose} className="px-6 py-2 bg-slate-800 text-white rounded-full font-bold">Cancel</button>
                <button onClick={simulateScan} className="px-6 py-2 bg-emerald-600 text-white rounded-full font-bold shadow-lg animate-bounce">
                    Simulate Capture
                </button>
            </div>
            <p className="mt-4 text-xs text-slate-500">Align QR code within the frame</p>
        </div>
    );
}

