      if (!process.env.API_KEY) return alert("API Key missing");
      setAiLoading(true);
      logAudit("vCISO Review", "Triggered Virtual CISO Review");
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const prompt = `You are a Virtual CISO (Chief Information Security Officer) with strict adherence to ISO 27001 and NCA ECC (Saudi Arabia).
          Review the following risk assessment.

          RISK DATA: ${JSON.stringify(currentRisk)}
          CONTEXT: ${JSON.stringify(context)}

          TASK:
          1. Evaluate if the mitigation plan is sufficient for the residual risk level.
          2. Check compliance with NCA ECC-1:2018.
          3. Provide a strategic decision: "APPROVE" or "REJECT".
          4. If approved, provide a short sign-off statement. If rejected, explain why.

          Format response as plain text, starting with decision.`;

          const response = await ai.models.generateContent({
              model: "gemini-2.5-flash",
              contents: prompt
          });

          const text = response.text || "";
          setAiOutput(text);
          setCurrentRisk(prev => ({...prev, vciso_feedback: text}));

          if (text.includes("APPROVE")) {
              const sigs = [...currentRisk.signatures];
