                onClose();
            }
        };
        startCamera();
        return () => {
             if (stream) stream.getTracks().forEach(track => track.stop());
        }
    }, [onClose]);

    // Simulate functionality since we can't reliably load a QR library without npm/cdn management constraints
    // In a real production environment, use 'jsQR' or 'html5-qrcode'
    const simulateScan = () => {
        setScanning(false);
        // Simulate a delay then return a "scanned" ID
        setTimeout(() => {
            onScan("R-LIB-01"); // Simulate finding a known risk ID
        }, 800);
    };

    return (
        <div className="fixed inset-0 z-[60] bg-black/95 flex flex-col items-center justify-center">
            <div className="relative w-full max-w-sm aspect-[3/4] bg-black rounded-lg overflow-hidden border border-slate-700 shadow-2xl">
                 <video ref={videoRef} className="w-full h-full object-cover opacity-80" playsInline muted></video>
                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                     <div className="w-64 h-64 border-2 border-emerald-500/50 rounded-xl relative">
                         <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-emerald-500"></div>
                         <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-emerald-500"></div>
                         <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-emerald-500"></div>
                         <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-emerald-500"></div>
                         {scanning && <div className="absolute top-1/2 left-4 right-4 h-0.5 bg-red-500 shadow-[0_0_15px_red] animate-pulse"></div>}
                     </div>
                 </div>
                 <div className="absolute bottom-8 inset-x-0 flex justify-center pointer-events-auto">
                     <button onClick={simulateScan} className="bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-3 rounded-full font-bold shadow-lg transform transition-transform hover:scale-105 active:scale-95 flex items-center gap-2">
                         <span>📷</span> Capture Code
                     </button>
                 </div>
            </div>
            <button onClick={onClose} className="mt-8 text-slate-400 hover:text-white underline">Cancel Scanning</button>
        </div>
    );
};

