  }, [context, riskRegister, currentRisk]);

  // Auth Observer
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setAuthLoading(true);
      if (currentUser && !currentUser.emailVerified) {
         await signOut(auth); setUser(null); setUserProfile(null);
      } else {
         setUser(currentUser);
         if (currentUser) {
            const snap = await getDoc(doc(db, "users", currentUser.uid));
            if (snap.exists()) setUserProfile(snap.data() as UserProfile);
            else {
                const p = { name: currentUser.displayName || "Anonymous", email: currentUser.email || "", photo_file_name: currentUser.photoURL || "" };
                await setDoc(doc(db, "users", currentUser.uid), p);
                setUserProfile(p);
            }
          }
      }
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  // Update calculated fields
  useEffect(() => {
    const inherent = calculateInherentRisk(currentRisk.likelihood_score, currentRisk.impact_score);
    const residual = calculateResidualRisk(inherent, currentRisk.control_effectiveness);
    const level = riskLevelFromScore(residual);

    if (inherent !== currentRisk.inherent_risk || residual !== currentRisk.residual_risk || level !== currentRisk.risk_level) {
      setCurrentRisk((prev) => ({ ...prev, inherent_risk: inherent, residual_risk: residual, risk_level: level }));
    }
  }, [currentRisk.likelihood_score, currentRisk.impact_score, currentRisk.control_effectiveness]);

  const logAudit = (action: string, details: string) => {
      const entry: AuditEntry = {
          timestamp: new Date().toISOString(),
          user: userProfile?.name || user?.email || "Guest",
          action,
          details
      };
      setCurrentRisk(prev => ({...prev, audit_trail: [entry, ...prev.audit_trail]}));
  };

  const handleRiskChange = (field: keyof Risk, value: any) => {
    const oldValue = (currentRisk as any)[field];
    if (oldValue !== value) {
        // Only log specific field changes to avoid spam
        if (['status', 'risk_level', 'control_effectiveness', 'treatment_option'].includes(field)) {
             logAudit("Field Updated", `Changed ${field} from '${oldValue}' to '${value}'`);
        }
        setCurrentRisk((prev) => ({ ...prev, [field]: value }));
    }
  };

  const saveRisk = () => {
    let updatedRegister;
    if (selectedRiskIndex !== null) {
      updatedRegister = [...riskRegister];
      updatedRegister[selectedRiskIndex] = { ...currentRisk };
    } else {
      updatedRegister = [...riskRegister, { ...currentRisk, id: Date.now().toString() }];
