    const newRisks = generateRiskLibrary();
    const updated = [...riskRegister, ...newRisks];
    setRiskRegister(updated);
  }

  const handleScan = (code: string) => {
      setShowScanner(false);
      const found = riskRegister.find(r => r.risk_id === code);
      if (found) {
          editRiskObj(found);
          alert(`Risk ${code} loaded.`);
      } else {
          alert(`Risk ID ${code} not found in register.`);
      }
  }

  const handleSign = (role: string) => {
      if(!user) return alert("Please sign in to digitally sign.");

      const idx = currentRisk.signatures.findIndex(s => s.role === role);
      if(idx === -1) return;

      const sigs = [...currentRisk.signatures];
      sigs[idx] = {
          ...sigs[idx],
          status: 'Signed',
          name: userProfile?.name || user.email || "Unknown",
          date: new Date().toISOString(),
          digital_id: Math.random().toString(36).substring(7).toUpperCase()
      };

      const entry: AuditEntry = {
          timestamp: new Date().toISOString(),
          user: userProfile?.name || user.email || "Guest",
          action: `Digital Signature: ${role}`
      };

      setCurrentRisk(prev => ({...prev, signatures: sigs, audit_trail: [entry, ...prev.audit_trail]}));
  };

  // --- Reports ---
  const generatePDF = () => {
      const doc = new jsPDF();
      const margin = 14;

      // Detailed Summary Section
      doc.setFontSize(22); doc.setTextColor(16, 185, 129); doc.text("Executive Risk Report", margin, 20);
