const AuthModal = ({ onClose }: { onClose: () => void }) => {
  const [view, setView] = useState<'login' | 'register' | 'verify' | 'forgotPassword'>('login');
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [verificationEmail, setVerificationEmail] = useState("");
  const [resetSent, setResetSent] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [repeatPassword, setRepeatPassword] = useState("");
  const [name, setName] = useState("");
  const [photoFile, setPhotoFile] = useState<File | null>(null);

  const resetForm = () => { setError(""); setEmail(""); setPassword(""); setRepeatPassword(""); setName(""); setPhotoFile(null); setResetSent(false); };
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => { if (e.target.files && e.target.files[0]) setPhotoFile(e.target.files[0]); };

  const handleGoogleLogin = async () => {
      setError("");
      setLoading(true);
      try {
          const provider = new GoogleAuthProvider();
          await signInWithPopup(auth, provider);
          onClose();
      } catch (err: any) {
          console.error("Google Auth Error:", err);
          setError(err.message || "Google Authentication failed");
      } finally {
          setLoading(false);
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault(); setError(""); setLoading(true);
    try {
      if (view === 'register') {
        if (password !== repeatPassword) throw new Error("Passwords do not match.");
        if (!name.trim()) throw new Error("Name is required.");
        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;
        let photoURL = "";
        if (photoFile) {
          const fileRef = ref(storage, `profile_photos/${user.uid}/${photoFile.name}`);
          await uploadBytes(fileRef, photoFile);
          photoURL = await getDownloadURL(fileRef);
        }
        await updateProfile(user, { displayName: name, photoURL: photoURL || "https://via.placeholder.com/150" });
        await sendEmailVerification(user);
        setVerificationEmail(user.email || email);
        await signOut(auth);
        setView('verify');
      } else if (view === 'forgotPassword') {
        if (!email) throw new Error("Please enter your email address.");
        await sendPasswordResetEmail(auth, email);
        setResetSent(true);
      } else {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;
        if (!user.emailVerified) { setVerificationEmail(user.email || email); await signOut(auth); setView('verify'); } 
        else { onClose(); }
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      setError(err.message || "Authentication failed");
    } finally { setLoading(false); }
  };

  if (view === 'verify') return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
        <div className="w-full max-w-md bg-slate-900 border border-slate-700 rounded-2xl p-8 text-center">
            <h2 className="text-xl font-bold text-white mb-4">Verify your Email</h2>
            <p className="text-slate-300 mb-6">Verification sent to {verificationEmail}</p>
            <button onClick={() => setView('login')} className="bg-emerald-600 text-white px-4 py-2 rounded">Log In</button>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
      <div className="w-full max-w-md bg-slate-900 border border-slate-700 rounded-2xl overflow-hidden shadow-2xl">
        <div className="bg-slate-800/50 p-6 border-b border-slate-700">
          <h2 className="text-xl font-bold text-white text-center">
              {view === 'register' ? "Create Account" : view === 'forgotPassword' ? "Reset Password" : "Welcome Back"}
          </h2>
        </div>

        {view === 'forgotPassword' && resetSent ? (
             <div className="p-6 text-center">
                <div className="text-4xl mb-4">📧</div>
                <p className="text-slate-300 mb-6">We sent you a password change link to <br/><span className="font-bold text-white">{email}</span></p>
                <button onClick={() => { setView('login'); setResetSent(false); setError(""); }} className="w-full bg-emerald-600 hover:bg-emerald-500 text-white p-2 rounded font-bold text-sm">Sign In</button>
            </div>
        ) : (
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
            {error && <div className="p-3 bg-red-500/10 text-red-400 rounded text-xs">{error}</div>}

            {view === 'register' && <input type="text" className="w-full bg-slate-950 border border-slate-700 p-2 rounded text-sm" placeholder="Full Name" value={name} onChange={e => setName(e.target.value)} />}

            <input type="email" className="w-full bg-slate-950 border border-slate-700 p-2 rounded text-sm" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />

            {view !== 'forgotPassword' && (
                <>
                <input type="password" className="w-full bg-slate-950 border border-slate-700 p-2 rounded text-sm" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} />
                {view === 'register' && <input type="password" className="w-full bg-slate-950 border border-slate-700 p-2 rounded text-sm" placeholder="Repeat Password" value={repeatPassword} onChange={e => setRepeatPassword(e.target.value)} />}
                </>
            )}

            {view === 'login' && (
                <div className="text-right">
                    <button type="button" onClick={() => { setView('forgotPassword'); setError(""); }} className="text-xs text-sky-400 hover:text-sky-300 hover:underline">Forgot password?</button>
                </div>
            )}

            <button type="submit" disabled={loading} className="w-full bg-sky-600 hover:bg-sky-500 text-white p-2 rounded font-bold text-sm">
                {loading ? "..." : (view === 'register' ? "Register" : view === 'forgotPassword' ? "Get Reset Link" : "Sign In")}
            </button>

            {view !== 'forgotPassword' && (
                <>
                    <div className="relative flex py-2 items-center">
                        <div className="flex-grow border-t border-slate-700"></div>
                        <span className="flex-shrink-0 mx-4 text-slate-500 text-xs">OR</span>
                        <div className="flex-grow border-t border-slate-700"></div>
                    </div>

                    <button 
                        type="button"
                        onClick={handleGoogleLogin}
                        className="w-full bg-white text-slate-900 p-2 rounded font-bold text-sm flex items-center justify-center gap-2 hover:bg-slate-100 transition-colors"
                    >
                        <img src="https://storage.googleapis.com/iso3001/metawork%20keylogo.webp" alt="Google" className="w-5 h-5" />
                        Sign in with Google
                    </button>
                </>
            )}

            </form>
        )}

        <div className="p-4 text-center border-t border-slate-700">
          {view === 'forgotPassword' ? (
              <button onClick={() => { setView('login'); setError(""); }} className="text-slate-500 text-xs hover:underline">Cancel</button>
          ) : (
            <>
                <button onClick={() => { setView(view === 'register' ? 'login' : 'register'); setError(""); }} className="text-sky-400 text-xs hover:underline">{view === 'register' ? "Login" : "Register"}</button>
                <button onClick={onClose} className="ml-4 text-slate-500 text-xs hover:underline">Cancel</button>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

