                </div>
                <label className="block text-slate-300">Asset<input className={getFieldClass('risk_asset')} value={currentRisk.asset} onChange={(e) => handleRiskChange("asset", e.target.value)} /></label>
                <label className="block text-slate-300">Threat<input className={getFieldClass('risk_threat')} value={currentRisk.threat} onChange={(e) => handleRiskChange("threat", e.target.value)} /></label>
                <label className="block text-slate-300">Vulnerability<input className={getFieldClass('risk_vuln')} value={currentRisk.vulnerability} onChange={(e) => handleRiskChange("vulnerability", e.target.value)} /></label>
                <label className="block text-slate-300">Risk Statement<textarea rows={2} className={getFieldClass('risk_statement')} value={currentRisk.risk_statement} onChange={(e) => handleRiskChange("risk_statement", e.target.value)} /></label>
            </div>
            <div className="space-y-2">
                <div className="grid grid-cols-3 gap-2">
