                <label className="block text-slate-300">Impact<select className={getFieldClass('risk_impact')} value={currentRisk.impact_score} onChange={(e) => handleRiskChange("impact_score", Number(e.target.value))}>{[1,2,3,4,5].map(v=><option key={v} value={v}>{v}</option>)}</select></label>
                <label className="block text-slate-300">Effectiveness<select className={getFieldClass('risk_effectiveness')} value={currentRisk.control_effectiveness} onChange={(e) => handleRiskChange("control_effectiveness", e.target.value)}><option value="weak">Weak</option><option value="medium">Medium</option><option value="strong">Strong</option></select></label>
