const App = () => {
  const [activeTab, setActiveTab] = useState<'assessment' | 'dashboard' | 'profile' | 'documents'>('assessment');
  const [context, setContext] = useState<ContextState>({
    organization: "", scope: "", risk_appetite: "", methodology: "qualitative", frameworks: ["ISO 31000"],
  });

  const [riskRegister, setRiskRegister] = useState<Risk[]>([]);
  const [currentRisk, setCurrentRisk] = useState<Risk>({ ...initialRiskState });
  const [isEditing, setIsEditing] = useState(false);
  const [selectedRiskIndex, setSelectedRiskIndex] = useState<number | null>(null);

  // Feature Modals State
  const [showScanner, setShowScanner] = useState(false);
  const [showSignature, setShowSignature] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showAudit, setShowAudit] = useState(false);

  const [searchTerm, setSearchTerm] = useState("");
  const [filterLevel, setFilterLevel] = useState("All");
  const [activeField, setActiveField] = useState<string | null>(null);

  const [aiOutput, setAiOutput] = useState("");
  const [aiLoading, setAiLoading] = useState(false);
  const [jsonOutput, setJsonOutput] = useState("");
  const [ttsLoading, setTtsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isLiveConnecting, setIsLiveConnecting] = useState(false);

  // Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const liveSessionRef = useRef<any>(null); 
  const nextStartTimeRef = useRef<number>(0);
  const liveSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const contextRef = useRef(context);
  const riskRegisterRef = useRef(riskRegister);
  const currentRiskRef = useRef(currentRisk);
  const selectedRiskIndexRef = useRef(selectedRiskIndex);

  const [user, setUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [showAuthModal, setShowAuthModal] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setAuthLoading(true);
      if (currentUser && !currentUser.emailVerified) { await signOut(auth); setUser(null); setUserProfile(null); } 
      else {
         setUser(currentUser);
         if (currentUser) {
            try {
              const docSnap = await getDoc(doc(db, "users", currentUser.uid));
              if (docSnap.exists()) setUserProfile(docSnap.data() as UserProfile);
              else {
                const newProfile = { name: currentUser.displayName || "Anonymous", email: currentUser.email || "", photo_file_name: currentUser.photoURL || "" };
                await setDoc(doc(db, "users", currentUser.uid), newProfile);
                setUserProfile(newProfile);
              }
            } catch (e) { console.error("Error fetching user profile:", e); }
          } else setUserProfile(null);
      }
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  const openAuthModal = () => setShowAuthModal(true);
  const closeAuthModal = () => setShowAuthModal(false);
  const logout = async () => { await signOut(auth); setActiveTab('assessment'); };
  const handleUpdateProfile = async (name: string, photo: string) => { /* ... */ };
  const handleDeleteAccount = async () => { /* ... */ };

  useEffect(() => {
    contextRef.current = context;
    riskRegisterRef.current = riskRegister;
    currentRiskRef.current = currentRisk;
    selectedRiskIndexRef.current = selectedRiskIndex;
  }, [context, riskRegister, currentRisk, selectedRiskIndex]);

  useEffect(() => {
    const inherent = calculateInherentRisk(currentRisk.likelihood_score, currentRisk.impact_score);
    const residual = calculateResidualRisk(inherent, currentRisk.control_effectiveness);
    const level = riskLevelFromScore(residual);
    if (inherent !== currentRisk.inherent_risk || residual !== currentRisk.residual_risk || level !== currentRisk.risk_level) {
      setCurrentRisk((prev) => ({ ...prev, inherent_risk: inherent, residual_risk: residual, risk_level: level }));
    }
  }, [currentRisk.likelihood_score, currentRisk.impact_score, currentRisk.control_effectiveness]);

  const handleContextChange = (field: keyof ContextState, value: any) => setContext((prev) => ({ ...prev, [field]: value }));

  const handleRiskChange = (field: keyof Risk, value: any) => {
      const oldVal = (currentRisk as any)[field];
      if (oldVal !== value) {
          const entry: AuditEntry = {
              timestamp: new Date().toISOString(),
              user: userProfile?.name || user?.email || "Guest",
              action: "Updated Field",
              field,
              oldValue: String(oldVal),
              newValue: String(value)
          };
          setCurrentRisk((prev) => ({ ...prev, [field]: value, audit_trail: [entry, ...prev.audit_trail] }));
      } else {
          setCurrentRisk((prev) => ({ ...prev, [field]: value }));
      }
  };

  const toggleFramework = (fw: string) => setContext(prev => ({ ...prev, frameworks: prev.frameworks.includes(fw) ? prev.frameworks.filter(f => f !== fw) : [...prev.frameworks, fw] }));

  const saveRisk = () => {
    let updatedRegister;
    if (selectedRiskIndex !== null) {
      updatedRegister = [...riskRegister];
      updatedRegister[selectedRiskIndex] = { ...currentRisk };
    } else {
      updatedRegister = [...riskRegister, { ...currentRisk, id: Date.now().toString() }];
    }
    setRiskRegister(updatedRegister);
    clearForm();
  };

  const editRiskObj = (risk: Risk) => {
      const idx = riskRegister.findIndex(r => r.id === risk.id);
      if (idx !== -1) {
          setSelectedRiskIndex(idx);
          setCurrentRisk({...riskRegister[idx]});
          setIsEditing(true);
      }
  }

  const clearForm = () => {
    setSelectedRiskIndex(null);
    setCurrentRisk({ ...initialRiskState });
    setIsEditing(false);
    setAiOutput("");
    setActiveField(null);
  };

  const loadLibrary = () => {
    const newRisks = generateRiskLibrary();
    const updated = [...riskRegister, ...newRisks];
    setRiskRegister(updated);
  }

  const handleScan = (code: string) => {
      setShowScanner(false);
      const found = riskRegister.find(r => r.risk_id === code);
      if (found) {
          editRiskObj(found);
          alert(`Risk ${code} loaded.`);
      } else {
          alert(`Risk ID ${code} not found in register.`);
      }
  }

  const handleSign = (role: string) => {
      if(!user) return alert("Please sign in to digitally sign.");

      const idx = currentRisk.signatures.findIndex(s => s.role === role);
      if(idx === -1) return;

      const sigs = [...currentRisk.signatures];
      const digitalId = Array.from(crypto.getRandomValues(new Uint8Array(8))).map(b => b.toString(16).padStart(2, '0')).join('').toUpperCase();

      sigs[idx] = {
          ...sigs[idx],
          status: 'Signed',
          name: userProfile?.name || user.email || "Unknown",
          date: new Date().toISOString(),
          digital_id: digitalId
      };

      const entry: AuditEntry = {
          timestamp: new Date().toISOString(),
          user: userProfile?.name || user.email || "Guest",
          action: `Digital Signature: ${role} [${digitalId}]`
      };

      const updatedRisk = {...currentRisk, signatures: sigs, audit_trail: [entry, ...currentRisk.audit_trail]};
      setCurrentRisk(updatedRisk);

      if (selectedRiskIndex !== null) {
          const updatedRegister = [...riskRegister];
          updatedRegister[selectedRiskIndex] = updatedRisk;
          setRiskRegister(updatedRegister);
      }
  };

  // --- Reports ---
  const generatePDF = () => {
      const doc = new jsPDF();
      const margin = 14;

      // Detailed Summary Section
      doc.setFontSize(22); doc.setTextColor(16, 185, 129); doc.text("Executive Risk Report", margin, 20);
      doc.setFontSize(10); doc.setTextColor(0);
      doc.text(`Generated: ${new Date().toLocaleString()}`, margin, 30);
      doc.text(`Organization: ${context.organization}`, margin, 35);

      // Synopsis Box
      doc.setFillColor(245, 247, 250);
      doc.rect(margin, 45, 182, 30, 'F');
      doc.setFontSize(12); doc.text("Executive Summary & Findings", margin + 5, 53);
      doc.setFontSize(9);
      const summary = `This report provides a comprehensive analysis of ${riskRegister.length} identified risks within the scope of ${context.scope}. Key Risk Indicators highlight ${riskRegister.filter(r => r.risk_level === 'Extreme').length} Extreme and ${riskRegister.filter(r => r.risk_level === 'High').length} High priority items. Compliance against ${context.frameworks.join(', ')} has been factored into the mitigation strategies.`;
      doc.text(doc.splitTextToSize(summary, 172), margin + 5, 60);

      // Signatures
      let y = 85;
      doc.setFontSize(11); doc.text("Approvals & Digital Signatures", margin, y);
      y += 8;

      const allSigs = riskRegister.flatMap(r => r.signatures).filter(s => s.status === 'Signed');
      if (allSigs.length > 0) {
          // Group signatures by Risk ID for clarity
          riskRegister.forEach(r => {
              const signed = r.signatures.filter(s => s.status === 'Signed');
              if (signed.length > 0) {
                   doc.setFontSize(9); doc.setFont("helvetica", "bold");
                   doc.text(`Risk ID: ${r.risk_id}`, margin, y);
                   y += 5;
                   signed.forEach(s => {
                       doc.setFontSize(8); doc.setFont("helvetica", "normal");
                       doc.text(`   • ${s.role}: ${s.name}`, margin, y);
                       doc.setTextColor(100);
                       doc.text(`     ${new Date(s.date).toLocaleString()} | ID: ${s.digital_id}`, margin + 60, y);
                       doc.setTextColor(0);
                       y += 5;
                   });
                   y += 2;
              }
          });
      } else {
          doc.setFontSize(8); doc.text("No digital signatures recorded.", margin, y);
          y += 4;
      }

      // Table
      const headers = [["ID", "Asset", "Threat", "Residual", "Status"]];
      const data = riskRegister.map(r => [r.risk_id, r.asset, r.threat, r.residual_risk.toString(), r.status]);
      autoTable(doc, { startY: y + 10, head: headers, body: data, theme: 'grid', headStyles: { fillColor: [16, 185, 129] } });
      doc.save(`Risk_Report_Exec_${new Date().toISOString().split('T')[0]}.pdf`);
  };

  const generateWord = async () => {
    const { Document, Packer, Paragraph, Table, TableRow, TableCell, WidthType, HeadingLevel, TextRun } = docx;
    const doc = new Document({
        sections: [{
            children: [
                new Paragraph({ text: "Executive Risk Report", heading: HeadingLevel.HEADING_1 }),
                new Paragraph({ text: "Executive Summary", heading: HeadingLevel.HEADING_2 }),
                new Paragraph({ text: `Organization: ${context.organization}` }),
                new Paragraph({ text: `Scope: ${context.scope}` }),
                new Paragraph({ text: `Key Indicators: ${riskRegister.filter(r => r.risk_level === 'Extreme').length} Extreme Risks` }),
                new Paragraph({ text: "Digital Signatures", heading: HeadingLevel.HEADING_2 }),
                ...riskRegister.flatMap(r => {
                    const signed = r.signatures.filter(s => s.status === 'Signed');
                    if(signed.length === 0) return [];
                    return [
                        new Paragraph({ text: `Risk: ${r.risk_id}`, heading: HeadingLevel.HEADING_3 }),
                        ...signed.map(s => new Paragraph({ text: `${s.role}: ${s.name} (${new Date(s.date).toLocaleDateString()}) [ID: ${s.digital_id}]` }))
                    ];
                }),
                new Paragraph({ text: "Risk Register", heading: HeadingLevel.HEADING_2, spacing: { before: 200 } }),
                new Table({
                    rows: [
                        new TableRow({ children: ["ID", "Threat", "Residual", "Status"].map(t => new TableCell({ children: [new Paragraph({text: t, bold: true})], shading: {fill: "10B981", color: "FFFFFF"} })) }),
