                            You are about to sign risk assessment <span className="text-emerald-400 font-mono">{risk.risk_id}</span>.
                        </p>
                        <div className="space-y-2">
                            {risk.signatures.map((sig, idx) => (
                                <div key={idx} 
                                    onClick={() => sig.status === 'Pending' && setSelectedRole(sig.role)}
                                    className={`flex justify-between items-center p-3 rounded border cursor-pointer transition-all ${
                                        sig.status === 'Signed' ? 'bg-slate-900 border-emerald-900/50 opacity-50' : 
                                        selectedRole === sig.role ? 'bg-sky-900/20 border-sky-500 ring-1 ring-sky-500' : 'bg-slate-950 border-slate-800 hover:border-slate-600'
                                    }`}>
                                    <div>
                                        <div className="font-bold text-sm text-white">{sig.role}</div>
                                        <div className="text-xs text-slate-500">
                                            {sig.status === 'Signed' ? 
                                                <span className="text-emerald-500">Signed by {sig.name}</span> : 
                                                'Pending Signature'
                                            }
                                        </div>
                                    </div>
                                    {sig.status === 'Signed' && <span className="text-emerald-500 text-lg">✓</span>}
                                    {sig.status === 'Pending' && selectedRole === sig.role && <span className="text-sky-500 text-lg">●</span>}
                                </div>
                            ))}
                        </div>
                    </div>

                    {selectedRole && (
                        <div className="animate-in fade-in slide-in-from-top-2">
                            <label className="flex gap-3 items-start p-3 bg-amber-900/10 border border-amber-900/30 rounded cursor-pointer">
                                <input type="checkbox" className="mt-1" checked={agreed} onChange={e => setAgreed(e.target.checked)} />
                                <span className="text-xs text-slate-300">
                                    I hereby certify that I have reviewed the risk assessment data. I approve the stated treatments and accept accountability for this role.
                                </span>
                            </label>

                            <button 
                                disabled={!agreed}
                                onClick={() => onSign(selectedRole)} 
                                className="mt-4 w-full py-2.5 bg-emerald-600 hover:bg-emerald-500 disabled:bg-slate-700 disabled:text-slate-500 text-white font-bold rounded shadow-lg transition-colors">
                                Digitally Sign as {selectedRole}
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

const HistoryModal = ({ risks, onClose, onSelect }: { risks: Risk[], onClose: () => void, onSelect: (r: Risk) => void }) => {
    return (
        <div className="fixed inset-0 z-[60] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="w-full max-w-4xl bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-2xl h-[80vh] flex flex-col">
                <div className="bg-slate-800 p-4 border-b border-slate-700 flex justify-between items-center">
                    <h3 className="font-bold text-white">Risk History</h3>
                    <button onClick={onClose} className="text-slate-400 hover:text-white">✕</button>
                </div>
                <div className="flex-1 overflow-y-auto p-4">
                    <table className="w-full text-left text-xs text-slate-300">
                        <thead className="text-slate-500 font-semibold border-b border-slate-800">
                            <tr><th className="p-2">ID</th><th className="p-2">Threat</th><th className="p-2">Level</th><th className="p-2">Status</th></tr>
                        </thead>
                        <tbody>
                            {risks.map(r => (
                                <tr key={r.id} onClick={() => { onSelect(r); onClose(); }} className="border-b border-slate-800 hover:bg-slate-800 cursor-pointer">
                                    <td className="p-2 font-mono text-emerald-400">{r.risk_id}</td>
                                    <td className="p-2">{r.threat}</td>
                                    <td className="p-2">{r.risk_level}</td>
                                    <td className="p-2">{r.status}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

const AuditModal = ({ risks, onClose }: { risks: Risk[], onClose: () => void }) => {
    const allLogs = risks.flatMap(r => r.audit_trail.map(a => ({...a, risk_id: r.risk_id})));
    return (
        <div className="fixed inset-0 z-[60] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="w-full max-w-2xl bg-slate-900 border border-slate-700 rounded-xl overflow-hidden shadow-2xl h-[70vh] flex flex-col">
                <div className="bg-slate-800 p-4 border-b border-slate-700 flex justify-between items-center">
                    <h3 className="font-bold text-white">Audit Trail</h3>
                    <button onClick={onClose} className="text-slate-400 hover:text-white">✕</button>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {allLogs.sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()).map((entry, i) => (
                        <div key={i} className="flex gap-3 text-xs border-b border-slate-800 pb-2">
                            <div className="text-slate-500 w-32 shrink-0">{new Date(entry.timestamp).toLocaleString()}</div>
                            <div className="flex-1">
                                <div className="font-bold text-emerald-400">{entry.risk_id || "System"}</div>
                                <div className="text-slate-300"><span className="text-sky-400 font-bold">{entry.user}</span> {entry.action}</div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

// --- Main App Components ---
const Dashboard = ({ risks }: { risks: Risk[] }) => (
    <div className="p-6 bg-slate-900 rounded-lg border border-slate-800 animate-in fade-in duration-500">
        <h2 className="text-xl font-bold mb-4">Dashboard</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <div className="bg-slate-800 p-4 rounded"><div className="text-slate-400 text-xs">Total Risks</div><div className="text-2xl font-bold">{risks.length}</div></div>
            <div className="bg-red-900/20 p-4 rounded border border-red-900/30"><div className="text-red-400 text-xs">Extreme</div><div className="text-2xl font-bold text-red-400">{risks.filter(r => r.risk_level === 'Extreme').length}</div></div>
            <div className="bg-orange-900/20 p-4 rounded border border-orange-900/30"><div className="text-orange-400 text-xs">High</div><div className="text-2xl font-bold text-orange-400">{risks.filter(r => r.risk_level === 'High').length}</div></div>
            <div className="bg-green-900/20 p-4 rounded border border-green-900/30"><div className="text-green-400 text-xs">Low</div><div className="text-2xl font-bold text-green-400">{risks.filter(r => r.risk_level === 'Low').length}</div></div>
        </div>
    </div>
);

const App = () => {
  const [activeTab, setActiveTab] = useState<'assessment' | 'dashboard' | 'profile' | 'documents'>('assessment');
  const [context, setContext] = useState<ContextState>({ organization: "", scope: "", risk_appetite: "", methodology: "qualitative", frameworks: ["ISO 31000"] });
  const [riskRegister, setRiskRegister] = useState<Risk[]>([]);
  const [currentRisk, setCurrentRisk] = useState<Risk>({ ...initialRiskState });
  const [selectedRiskIndex, setSelectedRiskIndex] = useState<number | null>(null);

  const [showScanner, setShowScanner] = useState(false);
  const [showSignature, setShowSignature] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showAudit, setShowAudit] = useState(false);

  const [aiOutput, setAiOutput] = useState("");
  const [aiLoading, setAiLoading] = useState(false);
  const [ttsLoading, setTtsLoading] = useState(false);

  const [user, setUser] = useState<User | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setUser(currentUser);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const inherent = calculateInherentRisk(currentRisk.likelihood_score, currentRisk.impact_score);
    const residual = calculateResidualRisk(inherent, currentRisk.control_effectiveness);
    const level = riskLevelFromScore(residual);
    if (inherent !== currentRisk.inherent_risk || residual !== currentRisk.residual_risk || level !== currentRisk.risk_level) {
      setCurrentRisk((prev) => ({ ...prev, inherent_risk: inherent, residual_risk: residual, risk_level: level }));
    }
  }, [currentRisk.likelihood_score, currentRisk.impact_score, currentRisk.control_effectiveness]);

  const handleFieldChange = (field: keyof Risk, value: any) => setCurrentRisk(prev => ({ ...prev, [field]: value }));
  const handleContextChange = (field: keyof ContextState, value: any) => setContext(prev => ({ ...prev, [field]: value }));

  const saveRisk = () => {
    if (selectedRiskIndex !== null) {
      const updated = [...riskRegister];
      updated[selectedRiskIndex] = { ...currentRisk };
      setRiskRegister(updated);
    } else {
      setRiskRegister([...riskRegister, { ...currentRisk, id: Date.now().toString() }]);
    }
    clearForm();
  };

  const clearForm = () => {
    setSelectedRiskIndex(null);
    setCurrentRisk({ ...initialRiskState });
    setAiOutput("");
  };

  const editRiskObj = (risk: Risk) => {
    const idx = riskRegister.findIndex(r => r.id === risk.id);
    if (idx !== -1) {
      setSelectedRiskIndex(idx);
      setCurrentRisk({ ...risk });
    }
  };

  const callGemini = async () => {
      if(!currentRisk.risk_statement && !currentRisk.threat) return alert("Please enter a threat or risk statement.");
      setAiLoading(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Act as a GRC expert (ISO 31000). For a risk with Threat: "${currentRisk.threat}", Asset: "${currentRisk.asset}", suggest 3 mitigation actions. Keep it concise.`
        });
        setAiOutput(response.text);
      } catch(e) { console.error(e); } finally { setAiLoading(false); }
  };

  const speakAiOutput = async () => {
      if(!aiOutput) return;
      setTtsLoading(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: aiOutput }] }],
            config: { responseModalities: [Modality.AUDIO], speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } } }
        });
        const base64 = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if(base64) {
            const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
            const buffer = await decodeAudioData(decode(base64), audioCtx, 24000, 1);
            const source = audioCtx.createBufferSource();
            source.buffer = buffer;
            source.connect(audioCtx.destination);
            source.start();
        }
      } catch(e) { console.error(e); } finally { setTtsLoading(false); }
  };

  const handleSign = (role: string) => {
      if(!user) return alert("Please sign in to digitally sign.");
      const sigs = [...currentRisk.signatures];
      const idx = sigs.findIndex(s => s.role === role);
      if(idx === -1) return;

      const digitalId = Math.random().toString(36).substring(7).toUpperCase();
      sigs[idx] = { ...sigs[idx], status: 'Signed', name: user.displayName || user.email || "User", date: new Date().toISOString(), digital_id: digitalId };

      const entry: AuditEntry = { timestamp: new Date().toISOString(), user: user.email || "User", action: `Digitally Signed as ${role}` };
      const updatedRisk = { ...currentRisk, signatures: sigs, audit_trail: [entry, ...currentRisk.audit_trail] };
      setCurrentRisk(updatedRisk);
      if (selectedRiskIndex !== null) {
          const updatedRegister = [...riskRegister];
          updatedRegister[selectedRiskIndex] = updatedRisk;
          setRiskRegister(updatedRegister);
      }
  };

  const generatePDF = () => {
      const doc = new jsPDF();
      doc.setFontSize(22); doc.setTextColor(16, 185, 129); doc.text("Risk Assessment Report", 14, 20);
      doc.setFontSize(10); doc.setTextColor(0); doc.text(`Organization: ${context.organization}`, 14, 30);
      const data = riskRegister.map(r => [r.risk_id, r.asset, r.threat, r.risk_level, r.status]);
      autoTable(doc, { startY: 40, head: [["ID", "Asset", "Threat", "Level", "Status"]], body: data });
      doc.save(`Risk_Report.pdf`);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-6 space-y-6 pb-24">
      {showAuthModal && <AuthModal onClose={() => setShowAuthModal(false)} />}
      {showScanner && <ScannerModal onScan={(code) => { setShowScanner(false); const f = riskRegister.find(r => r.risk_id === code); if(f) editRiskObj(f); }} onClose={() => setShowScanner(false)} />}
      {showSignature && <SignatureModal risk={currentRisk} onSign={handleSign} onClose={() => setShowSignature(false)} user={user} />}
      {showHistory && <HistoryModal risks={riskRegister} onClose={() => setShowHistory(false)} onSelect={editRiskObj} />}
      {showAudit && <AuditModal risks={riskRegister} onClose={() => setShowAudit(false)} />}

      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold">ISO 31000 Risk Dashboard</h1>
          <p className="text-sm text-slate-400">Professional GRC Management Tool</p>
        </div>
        <div className="flex gap-2">
            {!user ? <button onClick={() => setShowAuthModal(true)} className="px-3 py-1.5 bg-slate-800 text-sky-400 text-xs rounded-lg border border-slate-700">Sign In</button> : <button onClick={() => signOut(auth)} className="px-3 py-1.5 bg-slate-800 text-slate-400 text-xs rounded-lg border border-slate-700">Sign Out</button>}
            <button onClick={() => setActiveTab('assessment')} className={`px-3 py-1.5 text-xs rounded-lg ${activeTab === 'assessment' ? 'bg-emerald-500 text-slate-900' : 'bg-slate-800 text-slate-400'}`}>Assessment</button>
            <button onClick={() => setActiveTab('dashboard')} className={`px-3 py-1.5 text-xs rounded-lg ${activeTab === 'dashboard' ? 'bg-sky-500 text-slate-900' : 'bg-slate-800 text-slate-400'}`}>Dashboard</button>
        </div>
      </header>

      {activeTab === 'dashboard' && <Dashboard risks={riskRegister} />}
      {activeTab === 'assessment' && (
        <>
            <section className="bg-slate-900 p-4 rounded-xl border border-slate-800 grid md:grid-cols-2 gap-4 text-sm">
                <div className="space-y-2">
                    <label className="block text-slate-300">Organization<input className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={context.organization} onChange={e => handleContextChange('organization', e.target.value)} /></label>
                    <label className="block text-slate-300">Scope<input className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={context.scope} onChange={e => handleContextChange('scope', e.target.value)} /></label>
                </div>
                <div className="space-y-2">
                    <label className="block text-slate-300">Appetite<input className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={context.risk_appetite} onChange={e => handleContextChange('risk_appetite', e.target.value)} /></label>
                </div>
            </section>

            <section className="bg-slate-900 p-4 rounded-xl border border-slate-800 space-y-4">
                <div className="grid md:grid-cols-2 gap-4 text-sm">
                    <div className="space-y-2">
                        <label className="block text-slate-300">Risk ID<input className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={currentRisk.risk_id} onChange={e => handleFieldChange('risk_id', e.target.value)} /></label>
                        <label className="block text-slate-300">Asset<input className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={currentRisk.asset} onChange={e => handleFieldChange('asset', e.target.value)} /></label>
                        <label className="block text-slate-300">Threat<input className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={currentRisk.threat} onChange={e => handleFieldChange('threat', e.target.value)} /></label>
                    </div>
                    <div className="space-y-2">
                        <div className="grid grid-cols-2 gap-2">
                            <label className="block text-slate-300">Likelihood<select className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={currentRisk.likelihood_score} onChange={e => handleFieldChange('likelihood_score', Number(e.target.value))}>{[1,2,3,4,5].map(v => <option key={v} value={v}>{v}</option>)}</select></label>
                            <label className="block text-slate-300">Impact<select className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={currentRisk.impact_score} onChange={e => handleFieldChange('impact_score', Number(e.target.value))}>{[1,2,3,4,5].map(v => <option key={v} value={v}>{v}</option>)}</select></label>
                        </div>
                        <label className="block text-slate-300">Effectiveness<select className="w-full bg-slate-950 border border-slate-700 p-2 rounded" value={currentRisk.control_effectiveness} onChange={e => handleFieldChange('control_effectiveness', e.target.value)}><option value="weak">Weak</option><option value="medium">Medium</option><option value="strong">Strong</option></select></label>
                    </div>
                </div>
                <div className="flex justify-end gap-2">
                    <button onClick={clearForm} className="px-3 py-1.5 border border-slate-700 rounded text-xs">Clear</button>
                    <button onClick={saveRisk} className="px-4 py-1.5 bg-emerald-500 text-slate-900 font-bold rounded text-xs">{selectedRiskIndex !== null ? "Update" : "Save"}</button>
                </div>
            </section>

            <section className="bg-slate-900 rounded-xl border border-slate-800 overflow-hidden">
                <table className="w-full text-xs">
                    <thead className="bg-slate-800 text-slate-300">
                        <tr><th className="p-3 text-left">ID</th><th className="p-3 text-left">Asset</th><th className="p-3 text-left">Threat</th><th className="p-3 text-left">Level</th><th className="p-3 text-left">Status</th></tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800">
                        {riskRegister.map(r => (
                            <tr key={r.id} onClick={() => editRiskObj(r)} className="hover:bg-slate-800 cursor-pointer">
                                <td className="p-3 font-mono">{r.risk_id}</td><td className="p-3">{r.asset}</td><td className="p-3">{r.threat}</td>
                                <td className="p-3"><span className={`px-2 py-0.5 rounded ${r.risk_level === 'Extreme' ? 'bg-red-900/40 text-red-300' : 'bg-green-900/40 text-green-300'}`}>{r.risk_level}</span></td>
                                <td className="p-3">{r.status}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </section>

            <section className="grid md:grid-cols-2 gap-4">
                <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 space-y-2">
                    <div className="flex justify-between items-center"><h3 className="font-bold text-sm">AI Guidance</h3><div className="flex gap-2"><button onClick={speakAiOutput} className="text-xs">🔊</button><button onClick={callGemini} className="px-2 py-1 bg-sky-500 text-slate-900 rounded text-xs">{aiLoading ? "..." : "Suggest"}</button></div></div>
                    <textarea readOnly value={aiOutput} className="w-full bg-slate-950 p-2 h-32 rounded text-xs text-slate-400" placeholder="AI suggestions appear here..." />
                </div>
                <div className="bg-slate-900 p-4 rounded-xl border border-slate-800 flex flex-col items-center justify-center space-y-4">
                    <button onClick={generatePDF} className="w-full py-2 bg-red-600 rounded font-bold">Export PDF Report</button>
                    <p className="text-[10px] text-slate-500 text-center">Standard ISO 31000 Compliant Format</p>
                </div>
            </section>
        </>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-800 p-3 z-40 flex justify-center items-center gap-12 shadow-2xl">
          <button onClick={() => setShowScanner(true)} className="flex flex-col items-center text-slate-400 hover:text-emerald-400"><span className="text-xl">📷</span><span className="text-[10px]">SCAN</span></button>
          <button onClick={() => setShowHistory(true)} className="flex flex-col items-center text-slate-400 hover:text-sky-400"><span className="text-xl">📜</span><span className="text-[10px]">HISTORY</span></button>
          <button onClick={() => { if(!selectedRiskIndex && selectedRiskIndex !== 0) alert("Select a risk"); else setShowSignature(true); }} className="flex flex-col items-center text-slate-400 hover:text-indigo-400"><span className="text-xl">✒️</span><span className="text-[10px]">SIGN</span></button>
          <button onClick={() => setShowAudit(true)} className="flex flex-col items-center text-slate-400 hover:text-white"><span className="text-xl">📋</span><span className="text-[10px]">AUDIT</span></button>
      </footer>
    </div>
  );
};

const root = createRoot(document.getElementById("root")!);
root.render(<App />);
